INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0001-0000-0000-000000000000', 'acc03b00-0000-0000-0000-000000000001', 'text', '{"html":"<h3>What this course is about</h3><p>Welcome to <strong>SRVY 1341 — Land Surveying</strong>. This is a core, computation-heavy course in the determination of <strong>boundaries, areas, shapes, and locations</strong> through <strong>traversing</strong>. You will learn to measure distances and angles in the field, carry direction through a connected series of lines, detect and quantify error, <em>adjust</em> the work so it closes, and from the adjusted data compute <strong>coordinates</strong> and <strong>area</strong>. Those computed results become the numbers in a legal description and on a plat.</p><p>The unifying idea is the <strong>closed traverse</strong>: a connected loop (or link between known points) whose measurements can be mathematically checked. Everything else in the course either feeds the traverse (measurement, angles) or flows from it (coordinate geometry, area, boundary location).</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0001-0000-0000-000000000001', 'acc03b00-0000-0000-0000-000000000001', 'text', '{"html":"<h3>How the weeks fit together</h3><p>The semester builds in a deliberate order. Early weeks cover <strong>distance measurement</strong> (chaining and tape corrections) and <strong>direction</strong> (compass surveying, declination, angle types and measurement). The middle weeks turn to the heart of the course: <strong>latitudes and departures</strong>, <strong>error of closure</strong> and <strong>precision ratios</strong>, and the <strong>compass (Bowditch)</strong> and <strong>transit</strong> adjustment rules. After the midterm we apply the adjusted data through <strong>coordinate geometry</strong> (inversing and intersections) and <strong>area computation</strong> (coordinate and DMD methods), then study <strong>boundary determination</strong>, <strong>retracement</strong>, <strong>subdivision and curves</strong>, and <strong>professional standards</strong>.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0001-0000-0000-000000000002', 'acc03b00-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Bring a non-programmable and a programmable calculator. The Texas surveyor-in-training (SIT) and RPLS exams reward disciplined, step-by-step traverse computations — exactly the workflow this course drills."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0001-0000-0000-000000000003', 'acc03b00-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas context: Professional land surveying in Texas is regulated by the Texas Board of Professional Engineers and Land Surveyors (TBPELS) under Tex. Occ. Code ch. 1071, with standards of practice in 22 Texas Administrative Code ch. 138. Texas land descends from original General Land Office (GLO) surveys keyed to survey name + abstract number — Texas has no federal PLSS township-range grid."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0001-0000-0000-000000000004', 'acc03b00-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["The course centers on the closed traverse: measure, check, adjust, compute coordinates and area.","Weeks progress from measurement and direction, through adjustment, to coordinate geometry, area, and boundary work.","Texas surveying is regulated by TBPELS and rooted in the GLO original-survey system (no PLSS).","Redundant observations and a defensible record are the professional habits to build now."]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0002-0000-0000-000000000000', 'acc03b01-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Measuring distance by tape (chaining)</h3><p>Before EDM, distances were measured with a graduated steel <strong>tape</strong> (historically a <em>chain</em>, hence ''chaining''). Even today taping is essential for short ties, layout, and checks. The procedure stretches the tape between two points, holds it horizontal and under standard tension, and reads the distance. The art is in controlling the systematic errors that quietly bias every measurement: the tape is rarely exactly its nominal length, the temperature is rarely the standard temperature, the pull and the sag are rarely standard, and the ground is rarely level. Each of these produces a <strong>tape correction</strong> applied to the recorded distance.</p><p>Random errors (reading, marking, plumbing) are reduced by care and repetition; <strong>systematic errors</strong> are removed by computation. This lesson is about the systematic corrections.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0002-0000-0000-000000000001', 'acc03b01-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Standardization (length), temperature, tension, sag</h3><p><strong>Standardization:</strong> a tape is compared against a known standard; if a 100.00 ft tape is actually 100.02 ft, every full tape length is 0.02 ft too long and a correction proportional to length applies. <strong>Temperature:</strong> steel expands and contracts; the correction is <em>C<sub>t</sub> = &alpha;(T &minus; T<sub>0</sub>)L</em>, where &alpha; &asymp; 0.00000645 per &deg;F for steel and T<sub>0</sub> is the standardization temperature (usually 68&deg;F). <strong>Tension (pull):</strong> applying more or less than standard pull stretches the tape elastically; the correction depends on the cross-sectional area and modulus of elasticity. <strong>Sag:</strong> a tape supported only at its ends hangs in a catenary and reads <em>long</em> (the chord is shorter than the tape), so the sag correction is always negative.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0002-0000-0000-000000000002', 'acc03b01-0000-0000-0000-000000000001', 'equation', '{"latex":"C_t = \\alpha\\,(T - T_0)\\,L","label":"Temperature correction (steel: alpha = 0.00000645/°F)","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0002-0000-0000-000000000003', 'acc03b01-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Slope correction</h3><p>A tape stretched along sloping ground measures the <strong>slope distance</strong> <em>L</em>, but coordinate and area computations require the <strong>horizontal distance</strong> <em>H</em>. If the elevation difference between the tape ends is <em>h</em>, then exactly H = &radic;(L&sup2; &minus; h&sup2;). For gentle slopes the approximation H &asymp; L &minus; h&sup2;/(2L) is convenient and accurate. The slope correction (H &minus; L) is always negative: the horizontal distance is shorter than the slope distance. If instead the slope is given by a vertical (zenith) angle, H = L&middot;sin(zenith) or H = L&middot;cos(vertical angle).</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0002-0000-0000-000000000004', 'acc03b01-0000-0000-0000-000000000001', 'equation', '{"latex":"H = \\sqrt{L^2 - h^2}\\;\\approx\\; L - \\frac{h^2}{2L}","label":"Slope distance to horizontal distance","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0002-0000-0000-000000000005', 'acc03b01-0000-0000-0000-000000000001', 'table', '{"headers":["Correction","Sign / direction","Driver"],"rows":[["Standardization","+ if tape too long, - if too short","Actual vs. nominal tape length"],["Temperature","+ if hotter than T0, - if colder","alpha*(T - T0)*L"],["Tension (pull)","+ if pull > standard","Elastic stretch (area, modulus)"],["Sag","always - (tape reads long)","Catenary between supports"],["Slope","always - (H < L)","Elevation difference h"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0002-0000-0000-000000000006', 'acc03b01-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Sign rule of thumb: for MEASURING an unknown distance, if the tape is effectively too long the recorded distance is too SHORT, so add the correction. For LAYING OUT a known distance the rule reverses. State explicitly whether you are measuring or setting out."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0002-0000-0000-000000000007', 'acc03b01-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas context: historic Texas field notes and GLO grants are recorded in VARAS (1 vara = 33 1/3 in = 2.7778 ft; 36 varas = exactly 100 ft). When retracing an old survey you may convert varas to feet, but never blindly apply a non-Texas vara value to a Texas grant."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0002-0000-0000-000000000008', 'acc03b01-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Slope distance L reduced to horizontal distance H using elevation difference h."}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0002-0000-0000-000000000009', 'acc03b01-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Correct taped distances for standardization, temperature, tension, sag, and slope.","Temperature correction = alpha*(T - T0)*L; for steel alpha = 0.00000645 per deg F.","Sag and slope corrections are always negative; H = sqrt(L^2 - h^2).","1 vara = 2.7778 ft; 36 varas = 100 ft for Texas-record conversions.","Keep the measuring-vs-laying-out sign convention straight."]}'::jsonb, 9);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0003-0000-0000-000000000000', 'acc03b02-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Compass surveying and bearings</h3><p>A magnetic <strong>compass</strong> measures the horizontal direction of a line relative to <strong>magnetic north</strong>. Directions are recorded as <strong>bearings</strong>: a quadrant letter (N or S), an acute angle, and a second letter (E or W) &mdash; for example <em>N 42&deg;15'' E</em>. A bearing never exceeds 90&deg; because it is measured from the nearer end of the meridian. The reverse direction of a line (its <strong>back bearing</strong>) keeps the same angle but swaps both letters: the back bearing of N 42&deg;15'' E is S 42&deg;15'' W.</p><p>Compass work is the historical root of land surveying and still appears in old deeds, but it is <strong>low precision</strong> (subject to local attraction and limited to roughly a quarter-degree). Modern boundary surveys carry direction with a total station, not a compass; compass surveying in this course builds intuition and lets you read historic descriptions.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0003-0000-0000-000000000001', 'acc03b02-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Bearings vs. azimuths</h3><p>An <strong>azimuth</strong> is a direction measured <em>clockwise</em> from a reference meridian (usually north), ranging continuously from 0&deg; to 360&deg;. Azimuths are convenient for computation because the latitude/departure formulas (Lat = d cos Az, Dep = d sin Az) automatically produce the correct signs in all four quadrants. Bearings are convenient for description and recording. You will convert constantly between them: in the NE quadrant azimuth = bearing angle; in the SE quadrant azimuth = 180&deg; &minus; bearing; in the SW, azimuth = 180&deg; + bearing; in the NW, azimuth = 360&deg; &minus; bearing.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0003-0000-0000-000000000002', 'acc03b02-0000-0000-0000-000000000001', 'equation', '{"latex":"DD = D + \\frac{M}{60} + \\frac{S}{3600}","label":"Degrees-minutes-seconds to decimal degrees","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0003-0000-0000-000000000003', 'acc03b02-0000-0000-0000-000000000001', 'text', '{"html":"<h3>DD and DMS conversions</h3><p>Surveyors record angles in <strong>degrees, minutes, and seconds (DMS)</strong> but compute in <strong>decimal degrees (DD)</strong>. To convert <strong>DMS to DD</strong>, add the minutes divided by 60 and the seconds divided by 3600 to the whole degrees: 42&deg;15''30\" = 42 + 15/60 + 30/3600 = 42.2583&deg;. To convert <strong>DD to DMS</strong>, take the whole degrees, multiply the fraction by 60 for whole minutes, then multiply that fraction by 60 for seconds: 42.2583&deg; &rarr; 42&deg;, 0.2583&times;60 = 15.5'' &rarr; 15'', 0.5&times;60 = 30\" &rarr; 42&deg;15''30\". Carry enough decimal places; rounding a bearing too early can shift a long course by a meaningful distance.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0003-0000-0000-000000000004', 'acc03b02-0000-0000-0000-000000000001', 'table', '{"headers":["Quadrant","Bearing form","Azimuth from bearing angle B"],"rows":[["NE","N B E","Az = B"],["SE","S B E","Az = 180 - B"],["SW","S B W","Az = 180 + B"],["NW","N B W","Az = 360 - B"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0003-0000-0000-000000000005', 'acc03b02-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Quick check: a bearing is never larger than 90 degrees. If a ''bearing'' you computed exceeds 90, you forgot to fold it into the correct quadrant from its azimuth."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0003-0000-0000-000000000006', 'acc03b02-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas context: magnetic bearings in old Texas deeds were referenced to the magnetic north of the survey date and must be corrected for declination and secular change before retracement. The footsteps of the original surveyor govern, not a recomputed modern bearing (Stafford v. King, 30 Tex. 257)."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0003-0000-0000-000000000007', 'acc03b02-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Bearings: quadrant letter, acute angle (<=90), quadrant letter; back bearing swaps both letters.","Azimuths run clockwise 0-360 from north and give correct lat/dep signs automatically.","DMS to DD: DD = D + M/60 + S/3600; reverse by extracting degrees, minutes, then seconds.","Compass surveying is low precision and superseded by total stations for boundary work.","Old Texas magnetic bearings must be corrected for declination before retracement."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0004-0000-0000-000000000000', 'acc03b03-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Magnetic declination</h3><p><strong>Magnetic declination</strong> is the horizontal angle between <strong>magnetic north</strong> (where the compass points) and <strong>true (geodetic) north</strong>. It is <em>east</em> when magnetic north lies east of true north, and <em>west</em> otherwise. To convert a <strong>magnetic bearing to a true bearing</strong>, apply the declination: with <strong>east declination, add</strong> it; with <strong>west declination, subtract</strong> it (for bearings carefully tracked by quadrant). Declination varies by <strong>location</strong> and, crucially, by <strong>time</strong> &mdash; the so-called <strong>secular variation</strong> drifts the value by minutes per year. A bearing recorded magnetically in an 1870 GLO survey reflects that era''s declination, which is why retracing old work requires the historic value, not today''s.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0004-0000-0000-000000000001', 'acc03b03-0000-0000-0000-000000000001', 'equation', '{"latex":"\\text{True bearing} = \\text{Magnetic bearing} \\pm \\text{Declination}","label":"East declination added, west subtracted (track quadrant)","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0004-0000-0000-000000000002', 'acc03b03-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Smartphone compass apps</h3><p>Modern phones contain a three-axis <strong>magnetometer</strong> that powers compass apps. These are genuinely useful for <strong>reconnaissance</strong>: orienting a site sketch, finding an approximate bearing to a distant monument, or confirming which way a line runs. But they are <strong>not survey instruments</strong>. Phone magnetometers are easily disturbed by nearby steel (vehicles, rebar, the truck you are leaning on), require frequent figure-eight calibration, and typically deliver only a few degrees of accuracy. Treat the app as a pocket reconnaissance compass; never record a boundary bearing from a phone.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0004-0000-0000-000000000003', 'acc03b03-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Field notekeeping</h3><p>Field notes are a <strong>permanent, legal record</strong> of what was observed. The professional standards are simple and strict: notes are made <strong>contemporaneously</strong> in the field, in <strong>ink</strong>, in a bound book or a controlled digital collector; they are <strong>legible</strong> and complete enough that an independent surveyor could reconstruct the work; <strong>nothing is erased</strong> &mdash; an error is struck through with a single line and corrected, preserving the original. Each page records the date, party, weather, instrument, and a sketch with north arrow, station names, observed angles, distances, and descriptions of monuments found or set. Good notes are the difference between a defensible survey and an unprovable one.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0004-0000-0000-000000000004', 'acc03b03-0000-0000-0000-000000000001', 'table', '{"headers":["Tool / record","Survey-grade?","Appropriate use"],"rows":[["Magnetic compass","No (low precision)","Reconnaissance, historic bearing intuition"],["Smartphone compass app","No","Site orientation, rough azimuth to a monument"],["Total station / GNSS","Yes","Measured boundary angles and distances"],["Field notebook / data collector","Record","Permanent, legal record of observations"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0004-0000-0000-000000000005', 'acc03b03-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Professional development: reputable surveying trade publications (for example, The American Surveyor, POB - Point of Beginning, and xyHt) keep surveyors current on instruments, software, standards, and case law. Reading the trade press is part of the continuing-education habit TBPELS expects."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0004-0000-0000-000000000006', 'acc03b03-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas context: because Texas titles trace to original GLO surveys often recorded with magnetic bearings, retracement requires correcting historic magnetic bearings for the declination of the survey date. The controlling rule remains to follow the footsteps of the original surveyor, not to substitute a modern recomputed bearing (Stafford v. King, 30 Tex. 257)."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0004-0000-0000-000000000007', 'acc03b03-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Declination is the angle from magnetic north to true north; east is added, west subtracted (magnetic to true).","Declination varies by place and time (secular variation); historic survey dates matter for retracement.","Smartphone compass apps are reconnaissance aids, not survey instruments.","Field notes are a contemporaneous, ink, never-erased legal record; strike-through and correct errors.","Stay current through reputable surveying trade publications."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0005-0000-0000-000000000000', 'acc03b04-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Caring for a precision instrument</h3><p>A total station is a precision optical-electronic instrument that can cost as much as a vehicle, and its accuracy depends on staying in adjustment. Handle it by the <strong>standards (the uprights)</strong>, never by the telescope; remove it from the case by lifting straight up after loosening the clamps. Keep it <strong>dry</strong> &mdash; cover it in rain, and if it gets wet, dry it before casing to prevent fogging and corrosion. <strong>Never leave an instrument unattended on a tripod</strong>; wind, traffic, livestock, and curious passersby topple thousands of dollars in a second. Clean optics only with proper lens tissue, transport the instrument <strong>in its case</strong> (not on the tripod in a moving vehicle), and store it in a stable, dry environment.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0005-0000-0000-000000000001', 'acc03b04-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Tripod best practices</h3><p>The tripod is the literal foundation of every measurement, and tripod faults masquerade as measurement error. Spread the legs to a <strong>stable, roughly equal</strong> angle and press each <strong>firmly into the ground</strong> so it cannot settle or creep during the setup. Tighten the <strong>leg clamps</strong> snugly &mdash; a loose leg lets the instrument sag and drift mid-observation. Keep the <strong>tripod head</strong> approximately level before mounting the instrument so the fine leveling has range to work. Mount the instrument and immediately <strong>snug the centering screw</strong>. On hard surfaces, guard against the legs sliding; on soft ground, beware of slow settlement that opens an angle between backsight and foresight. A drifting setup is one of the most common sources of an unexplained traverse misclosure.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0005-0000-0000-000000000002', 'acc03b04-0000-0000-0000-000000000001', 'table', '{"headers":["Practice","Why it matters"],"rows":[["Lift by the standards, not the telescope","Protects the telescope and axes from strain"],["Firm, equal-tension tripod legs","Prevents settlement and mid-setup drift"],["Level the tripod head first","Gives the leveling screws working range"],["Never leave instrument unattended","Avoids catastrophic tip-overs"],["Transport in the case","Prevents shock and de-adjustment"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0005-0000-0000-000000000003', 'acc03b04-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Daily field checks: verify the plate (tubular/electronic) level, the optical or laser plummet, and that all clamps and tangent screws move smoothly. A two-minute check at the truck saves a wasted day of biased data."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0005-0000-0000-000000000004', 'acc03b04-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Maintenance and calibration schedules</h3><p>Beyond daily care, instruments need a <strong>scheduled</strong> regimen. <strong>Daily/weekly</strong>: clean optics and housings, check battery health, confirm plate level and plummet, and run a quick collimation check. <strong>Periodically</strong> (and after any shock or temperature extreme): perform field adjustments for line-of-sight (horizontal) collimation, vertical-index error, and tilt sensor. <strong>Annually or per manufacturer interval</strong>: send the instrument to an authorized service center for full calibration against traceable standards, and <strong>keep the calibration certificate</strong>. EDM accuracy should be verified on a known baseline. A documented schedule and retained records demonstrate that the data behind a survey was produced by an instrument in tolerance &mdash; useful if the work is ever challenged.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0005-0000-0000-000000000005', 'acc03b04-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas context: TBPELS standards of practice (22 TAC ch. 138) require that surveys meet stated accuracy standards. Using an out-of-adjustment instrument, or failing to document calibration, can undermine the defensibility of a survey if it is challenged."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0005-0000-0000-000000000006', 'acc03b04-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Handle instruments by the standards, keep them dry, transport in the case, never leave unattended on a tripod.","A firm, level, equal-tension tripod with snug clamps prevents settlement and drift.","Run daily field checks (level, plummet, collimation) to catch drift early.","Follow daily/periodic/annual maintenance and professional-calibration schedules; keep records.","Documented in-tolerance instruments support a defensible survey under TBPELS standards."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0006-0000-0000-000000000000', 'acc03b05-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The setup loop</h3><p>Setting up a total station precisely over a point is a learned, iterative skill. The sequence is: (1) <strong>set the tripod</strong> roughly centered and level over the mark, legs firm; (2) <strong>rough-center</strong> using the optical or laser <strong>plummet</strong>, adjusting tripod-leg lengths to bring the bubble of the circular level approximately in while keeping the plummet near the point; (3) <strong>coarse-level</strong> with the circular (bull''s-eye) bubble by leg adjustment; (4) <strong>fine-level</strong> with the <strong>leveling screws</strong> against the plate level; (5) <strong>re-center</strong> precisely by loosening the tribrach and <em>sliding</em> the instrument on the tripod head until the plummet is exactly on the mark. Because leveling and centering interact, you iterate steps 4 and 5 until both are satisfied simultaneously.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0006-0000-0000-000000000001', 'acc03b05-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Fine leveling with the screws</h3><p>Fine leveling follows a fixed routine that exploits the three leveling screws. <strong>First</strong>, rotate the alidade until the <strong>plate level</strong> is parallel to a line through <em>two</em> of the screws; turn those two screws in <em>opposite</em> directions to center the bubble (the bubble follows your left thumb). <strong>Second</strong>, rotate the instrument <strong>90&deg;</strong> so the level lies over the <em>third</em> screw; use only that screw to center the bubble. <strong>Third</strong>, return and check; repeat until the bubble stays centered in <em>all</em> directions. With an electronic level, the display guides the same two-then-one screw motions. A correctly leveled instrument has its vertical axis truly vertical, which is what makes horizontal angles meaningful.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0006-0000-0000-000000000002', 'acc03b05-0000-0000-0000-000000000001', 'equation', '{"latex":"e_{ang} \\approx \\frac{e_c}{D}\\;\\text{(rad)} = \\frac{e_c}{D}\\times 206265\\;\\text{(arc-sec)}","label":"Angular error from a centering error e_c at sight distance D","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0006-0000-0000-000000000003', 'acc03b05-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Why setup precision matters</h3><p>A small <strong>centering error</strong> <em>e<sub>c</sub></em> (the instrument off the mark) introduces an angular error that grows as the sight distance <em>D</em> shrinks: the angular error in radians is roughly <em>e<sub>c</sub>/D</em>, or e<sub>c</sub>/D &times; 206265 in arc-seconds. Miscentering by 0.005 ft (about 1.5 mm) on a 100-ft sight is about 10 arc-seconds of angular error; on a 20-ft sight it is five times worse. This is why short sights and careless centering are so damaging, and why the field-procedure lesson stressed balanced, not-too-short courses. Finally, record the <strong>height of instrument (HI)</strong> &mdash; the vertical distance from the ground mark to the instrument''s trunnion axis &mdash; because it feeds trigonometric leveling and 3D coordinate reductions.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0006-0000-0000-000000000004', 'acc03b05-0000-0000-0000-000000000001', 'table', '{"headers":["Step","Tool used","Goal"],"rows":[["Rough setup","Tripod legs + plummet","Roughly over point, head level"],["Coarse level","Circular (bull''s-eye) bubble","Approximately level"],["Fine level","Plate level + leveling screws","Vertical axis truly vertical"],["Precise centering","Plummet + slide on tribrach","Exactly over the mark"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0006-0000-0000-000000000005', 'acc03b05-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Two-then-one rule: with the plate level over two screws, turn both (opposite directions) to center; rotate 90 degrees and use only the third screw. The bubble moves toward your left thumb."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0006-0000-0000-000000000006', 'acc03b05-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Leveling and centering a total station over a point."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0006-0000-0000-000000000007', 'acc03b05-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Setup iterates: rough-center, coarse-level, fine-level with screws, then slide to center exactly.","Fine leveling: two screws (opposite) to center, rotate 90 deg, third screw, then recheck.","Centering error of e_c at sight D gives angular error ~ e_c/D (rad); worst on short sights.","A truly vertical axis is what makes horizontal angles valid.","Record the height of instrument (HI) for trigonometric leveling and 3D reductions."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0007-0000-0000-000000000000', 'acc03b06-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Kinds of angles</h3><p>Surveyors measure horizontal angles in several conventions. An <strong>interior angle</strong> is measured inside a closed polygon at each station; for an <em>n</em>-sided closed traverse the interior angles must sum to <strong>(n &minus; 2) &times; 180&deg;</strong>. An <strong>exterior angle</strong> is its supplement outside the polygon; exterior angles sum to <strong>(n + 2) &times; 180&deg;</strong>. A <strong>deflection angle</strong> is measured right (R) or left (L) from the <em>prolongation</em> of the preceding course &mdash; favored on route surveys; for a closed loop the deflection angles algebraically sum to <strong>360&deg;</strong>. An <strong>angle to the right</strong> is the clockwise angle from the backsight to the foresight and is the dominant convention for modern total-station traverses because it carries direction unambiguously.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0007-0000-0000-000000000001', 'acc03b06-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Carrying azimuth through a traverse</h3><p>Once you observe angles to the right, you can propagate <strong>azimuths</strong> around the traverse. The rule is: the <strong>forward azimuth of the next course equals the back azimuth of the current course plus the measured angle to the right</strong>, reduced modulo 360&deg;. The back azimuth is the forward azimuth &plusmn; 180&deg;. Starting from one known azimuth, you can compute the azimuth of every course, and from each azimuth the corresponding bearing. This computation is the bridge from raw angle observations to the directions needed for latitudes and departures.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0007-0000-0000-000000000002', 'acc03b06-0000-0000-0000-000000000001', 'equation', '{"latex":"\\text{Az}_{next} = (\\text{Az}_{prev} \\pm 180^\\circ + \\text{angle right}) \\bmod 360^\\circ","label":"Azimuth propagation using angles to the right","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0007-0000-0000-000000000003', 'acc03b06-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Controlling instrumental error</h3><p>No instrument is perfect, so angles are observed to <strong>cancel</strong> systematic errors. Observing on both telescope faces &mdash; <strong>face-left (direct)</strong> and <strong>face-right (reversed)</strong>, abbreviated <strong>D&amp;R</strong> &mdash; and averaging eliminates <em>line-of-sight (collimation)</em> error and <em>horizontal-axis (trunnion)</em> error, because those errors flip sign between faces. <strong>Repeating</strong> the angle several times and averaging reduces random pointing and reading error. <strong>Closing the horizon</strong> (turning all the way around the point so the angles total 360&deg;) catches blunders on station. Together these habits turn a good instrument into trustworthy data and are expected on any boundary or control traverse.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0007-0000-0000-000000000004', 'acc03b06-0000-0000-0000-000000000001', 'table', '{"headers":["Angle type","Reference","Closed-loop sum"],"rows":[["Interior angle","Inside the polygon","(n - 2) x 180 deg"],["Exterior angle","Outside the polygon","(n + 2) x 180 deg"],["Deflection angle","Prolongation of prior course (R/L)","360 deg (algebraic)"],["Angle to the right","Clockwise BS to FS","n/a (propagates azimuth)"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0007-0000-0000-000000000005', 'acc03b06-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Angular closure check: for a closed loop, compare the sum of measured interior angles with (n-2)*180. Distribute the small angular misclosure equally among the angles BEFORE computing azimuths and lat/dep."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0007-0000-0000-000000000006', 'acc03b06-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas context: TBPELS standards (22 TAC ch. 138) expect angular observations adequate to meet the survey''s accuracy class. For boundary work, document repetition and both-face observation; a single un-repeated angle is poor practice if challenged."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0007-0000-0000-000000000007', 'acc03b06-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Interior angles sum to (n-2)*180; exterior to (n+2)*180; deflection angles to 360 deg.","Angle to the right (clockwise BS to FS) is the modern convention.","Az_next = (Az_prev +/- 180 + angle right) mod 360.","Face-left/face-right (D&R) cancels collimation and trunnion-axis errors; repetition reduces random error.","Check angular closure and distribute the small misclosure before computing azimuths."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0008-0000-0000-000000000000', 'acc03b07-0000-0000-0000-000000000001', 'text', '{"html":"<h3>From courses to misclosure</h3><p>To adjust a traverse you first resolve each course into a <strong>latitude</strong> (north-south component, Lat = d cos &alpha;) and a <strong>departure</strong> (east-west component, Dep = d sin &alpha;). For a closed-loop traverse the latitudes should sum to zero and the departures should sum to zero. The small residual sums are the <strong>misclosure in latitude</strong> (E<sub>L</sub> = &Sigma;Lat) and the <strong>misclosure in departure</strong> (E<sub>D</sub> = &Sigma;Dep). Their hypotenuse, E = hypot(E<sub>L</sub>, E<sub>D</sub>), is the <strong>linear misclosure</strong>, and perimeter &divide; E gives the <strong>ratio of closure</strong> 1:N. Adjustment distributes E<sub>L</sub> and E<sub>D</sub> back into the courses so the traverse closes &mdash; but only after the ratio of closure passes and any blunder has been hunted out.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0008-0000-0000-000000000001', 'acc03b07-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Compass (Bowditch) rule</h3><p>The <strong>compass</strong> or <strong>Bowditch rule</strong> is the workhorse adjustment. It assumes the precision of <strong>angles and distances is comparable</strong>, so accumulated error is proportional to course <strong>length</strong>. The correction to a course''s latitude is &minus;E<sub>L</sub>&times;(d<sub>i</sub>/P) and to its departure is &minus;E<sub>D</sub>&times;(d<sub>i</sub>/P), where P is the perimeter. Longer courses receive proportionally larger corrections. After applying them, the adjusted latitudes and departures each sum to zero. The compass rule fits ordinary total-station boundary traverses, where angles and EDM distances are observed to similar relative precision, and is the default in most software.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0008-0000-0000-000000000002', 'acc03b07-0000-0000-0000-000000000001', 'equation', '{"latex":"C_{\\text{Lat},i} = -E_L\\,\\frac{d_i}{P}, \\qquad C_{\\text{Dep},i} = -E_D\\,\\frac{d_i}{P}","label":"Compass (Bowditch) rule corrections","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0008-0000-0000-000000000003', 'acc03b07-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Transit rule</h3><p>The <strong>transit rule</strong> rests on a different assumption: the <strong>angles are measured more precisely than the distances</strong>. Because distance error dominates, the misclosure is distributed in proportion to the <strong>magnitude of each course''s latitude and departure</strong> rather than its length: C<sub>Lat,i</sub> = &minus;E<sub>L</sub>&times;(|Lat<sub>i</sub>|/&Sigma;|Lat|) and C<sub>Dep,i</sub> = &minus;E<sub>D</sub>&times;(|Dep<sub>i</sub>|/&Sigma;|Dep|). The two components are weighted <em>independently</em>. A practical signature is that the transit rule disturbs the computed <strong>bearings less</strong> than the compass rule (it holds directions, pushes lengths). Its weakness is erratic behavior when a course''s latitude or departure is near zero (a nearly E-W or N-S line), so modern practice rarely prefers it.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0008-0000-0000-000000000004', 'acc03b07-0000-0000-0000-000000000001', 'equation', '{"latex":"C_{\\text{Lat},i} = -E_L\\,\\frac{|\\text{Lat}_i|}{\\sum|\\text{Lat}|}, \\qquad C_{\\text{Dep},i} = -E_D\\,\\frac{|\\text{Dep}_i|}{\\sum|\\text{Dep}|}","label":"Transit rule corrections","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0008-0000-0000-000000000005', 'acc03b07-0000-0000-0000-000000000001', 'table', '{"headers":["Aspect","Compass (Bowditch)","Transit","Least squares"],"rows":[["Assumption","Angle/distance precision comparable","Angles better than distances","Each observation weighted by its precision"],["Weighting","Course length d_i/P","|Lat_i| and |Dep_i| shares","Inverse variance (rigorous)"],["Effect on bearings","Shift more","Shift less","Statistically optimal"],["Modern use","Common default","Classical / niche","Professional standard for control"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0008-0000-0000-000000000006', 'acc03b07-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Other methods: the Crandall rule (holds angles fixed, adjusts distances by least squares) and the rigorous least-squares adjustment generalize these ideas. Least squares also yields error ellipses that describe the positional uncertainty of each station."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0008-0000-0000-000000000007', 'acc03b07-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas context: Always confirm the ratio of closure meets the required standard for the survey class (TBPELS 22 TAC ch. 138 and the TSPS Manual of Practice) BEFORE adjusting. Spreading an undetected blunder across all courses corrupts otherwise-good boundary data."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0008-0000-0000-000000000008', 'acc03b07-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Compute Lat = d cos(bearing), Dep = d sin(bearing); misclosure E = hypot(sum Lat, sum Dep).","Compass rule weights corrections by course length (d_i/P).","Transit rule weights by component magnitude (|Lat|, |Dep|) and disturbs bearings less.","The transit rule misbehaves when a component is near zero; least squares is the rigorous modern choice.","Verify the ratio of closure and hunt blunders BEFORE adjusting."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0009-0000-0000-000000000000', 'acc03b08-0000-0000-0000-000000000001', 'text', '{"html":"<h3>What the midterm covers</h3><p>The midterm assesses the <strong>first half</strong> of SRVY 1341, Weeks 1-7. Expect a balance of conceptual questions and computations drawn from: <strong>distance measurement</strong> and tape corrections (standardization, temperature, sag, slope); <strong>compass surveying</strong>, bearings vs. azimuths, and <strong>DD/DMS</strong> conversions; <strong>magnetic declination</strong> and field-note standards; <strong>instrument care, setup, and leveling</strong>; <strong>types of angles</strong> and azimuth propagation; and the heart of the half &mdash; <strong>latitudes and departures</strong>, <strong>misclosure</strong>, <strong>ratio of closure</strong>, and the <strong>compass (Bowditch)</strong> and <strong>transit</strong> adjustment rules.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0009-0000-0000-000000000001', 'acc03b08-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The computation you must own</h3><p>The single most important skill is the <strong>short-traverse workflow</strong>. Given a few courses (bearings and horizontal distances) you should be able to, without hesitation: (1) resolve each into latitude and departure with correct signs; (2) sum to get E<sub>L</sub> and E<sub>D</sub>; (3) compute the linear misclosure E = hypot(E<sub>L</sub>, E<sub>D</sub>); (4) report the ratio of closure 1:N = perimeter/E; and (5) apply the compass or transit corrections and confirm the adjusted sums close to zero. Practice until each step is automatic and you can carry the units and a self-check through cleanly.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0009-0000-0000-000000000002', 'acc03b08-0000-0000-0000-000000000001', 'table', '{"headers":["Topic block","Weeks","Be able to..."],"rows":[["Distance & corrections","1","Correct a taped distance; reduce slope to horizontal"],["Direction & angles","2,3,6","Convert DMS/DD, bearings/azimuths; propagate azimuth"],["Declination & notes","3","Convert magnetic to true; keep proper field notes"],["Instruments","4,5","Care, setup, level, and center over a point"],["Traverse adjustment","7","Lat/dep, misclosure, ratio, compass & transit"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0009-0000-0000-000000000003', 'acc03b08-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Exam strategy: write the governing formula first, substitute with units, then evaluate. A labeled, step-by-step solution earns partial credit even if a single arithmetic slip occurs."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0009-0000-0000-000000000004', 'acc03b08-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas context: licensure exams (the Fundamentals/SIT and the Texas RPLS exams administered under TBPELS) reward exactly this disciplined traverse workflow. Building the habit now pays off at the board exam."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0009-0000-0000-000000000005', 'acc03b08-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Midterm spans Weeks 1-7: measurement, direction, angles, instruments, and adjustment.","Own the short-traverse workflow: lat/dep -> misclosure -> ratio -> adjust.","Write the formula, substitute with units, evaluate, and check.","Review by re-working problems; partial credit rewards clear steps."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0010-0000-0000-000000000000', 'acc03b09-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The inverse: distance and direction from coordinates</h3><p><strong>Coordinate geometry (COGO)</strong> works the traverse problem in reverse. Given two points with coordinates (N<sub>1</sub>, E<sub>1</sub>) and (N<sub>2</sub>, E<sub>2</sub>), the <strong>inverse</strong> computes the <strong>distance</strong> and <strong>azimuth</strong> between them. The differences are &Delta;N = N<sub>2</sub> &minus; N<sub>1</sub> (the latitude) and &Delta;E = E<sub>2</sub> &minus; E<sub>1</sub> (the departure). The distance is the hypotenuse, distance = hypot(&Delta;E, &Delta;N), and the azimuth is atan2(&Delta;E, &Delta;N) &mdash; note the <em>departure-over-latitude</em> order, because azimuth is measured clockwise from north. Reduce a negative result by adding 360&deg;. The inverse is the everyday tool for computing a course between any two known points: corner to corner, control to corner, or instrument to a stake-out target.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0010-0000-0000-000000000001', 'acc03b09-0000-0000-0000-000000000001', 'equation', '{"latex":"\\text{dist} = \\sqrt{\\Delta E^2 + \\Delta N^2}, \\qquad \\text{Az} = \\operatorname{atan2}(\\Delta E,\\ \\Delta N)","label":"Inverse: distance and azimuth between two points","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0010-0000-0000-000000000002', 'acc03b09-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Intersections</h3><p>An <strong>intersection</strong> finds a new point from two lines of constraint. In a <strong>bearing-bearing intersection</strong>, two known points each emit a line of known direction (azimuth); the new point is where the lines cross &mdash; solved by writing each line parametrically and equating, or by the law of sines on the triangle the two stations form. In a <strong>bearing-distance (direction-distance) intersection</strong>, you know a direction from one point and a distance from another (a line meets a circle, giving up to two solutions). In a <strong>distance-distance intersection</strong>, two known distances from two known points locate the new point (two circles, up to two intersections) &mdash; the basis of trilateration. Intersections are how surveyors compute corner positions, set out points from multiple ties, and resolve geometry that was not directly measured.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0010-0000-0000-000000000003', 'acc03b09-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Using COGO to check and lay out</h3><p>COGO is both a <strong>computation</strong> and a <strong>checking</strong> tool. After adjusting a traverse you can inverse between any two stations and compare the computed course against the field-measured one; a discrepancy flags a blunder. For layout (stake-out), you inverse from the occupied instrument point to the design point to get the azimuth and distance to turn and measure. Modern data collectors run these COGO routines continuously, but you must understand the underlying trigonometry to set them up correctly, recognize a wrong answer, and defend the geometry. The inverse and the intersection are the two COGO operations you will use most.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0010-0000-0000-000000000004', 'acc03b09-0000-0000-0000-000000000001', 'table', '{"headers":["Problem","Known","Solves for","Solutions"],"rows":[["Inverse","Two coordinated points","Distance & azimuth","1"],["Bearing-bearing","Two points + two directions","Intersection point","1"],["Bearing-distance","One direction + one distance","Point (line meets circle)","up to 2"],["Distance-distance","Two distances (trilateration)","Point (two circles)","up to 2"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0010-0000-0000-000000000005', 'acc03b09-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Watch the atan2 argument order: azimuth from north uses atan2(departure, latitude) = atan2(dE, dN). Swapping the arguments gives the angle from the east axis instead — a classic COGO mistake."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0010-0000-0000-000000000006', 'acc03b09-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas context: COGO coordinates for boundary work are normally carried on the Texas State Plane Coordinate System (NAD83). Remember that grid azimuths and distances differ from geodetic/ground values; track whether you are working in grid or ground (TBPELS 22 TAC ch. 138)."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0010-0000-0000-000000000007', 'acc03b09-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Bearing-bearing intersection of two known points."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0010-0000-0000-000000000008', 'acc03b09-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Inverse: distance = hypot(dE, dN); azimuth = atan2(dE, dN), reduced to 0-360.","Use atan2(departure, latitude) order so the azimuth is from north.","Bearing-bearing gives one intersection; bearing-distance and distance-distance give up to two.","Inverse between adjusted stations to check field work; inverse from instrument to design point to stake out.","Track grid vs. ground when working on the Texas State Plane Coordinate System."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0011-0000-0000-000000000000', 'acc03b10-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Area by coordinates (shoelace)</h3><p>Once a traverse is <strong>balanced</strong> and every corner has coordinates, the parcel area follows directly from the <strong>coordinate (shoelace) method</strong>. Taking the corners in order around the perimeter (consistently clockwise or counterclockwise), the area is half the absolute value of the sum of cross-products x<sub>i</sub>y<sub>i+1</sub> &minus; x<sub>i+1</sub>y<sub>i</sub>, with indices cycling so the last corner closes back to the first. The method is exact for any simple closed polygon and is the modern computation of choice. The <em>balance-first</em> rule is essential: an unadjusted figure does not close, and its ''area'' silently includes the misclosure gap.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0011-0000-0000-000000000001', 'acc03b10-0000-0000-0000-000000000001', 'equation', '{"latex":"A = \\tfrac{1}{2}\\left|\\sum_{i=1}^{n}(x_i\\,y_{i+1} - x_{i+1}\\,y_i)\\right|","label":"Area by coordinates (shoelace), indices cyclic","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0011-0000-0000-000000000002', 'acc03b10-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Double meridian distance (DMD)</h3><p>The <strong>double-meridian-distance (DMD)</strong> method is the classical hand-tabulation that predates coordinates and gives the <em>same</em> answer. The <strong>meridian distance</strong> of a course is the perpendicular distance from a reference meridian to the course''s midpoint; doubling it avoids fractions. The DMD of the first course equals its own departure; each subsequent DMD equals the previous DMD plus the previous departure plus the current departure. The area is then A = &frac12;|&Sigma;(DMD<sub>i</sub> &times; Lat<sub>i</sub>)|. DMD is worth knowing because old records, exams, and some software trace to it, and because it reinforces how latitudes and departures encode area.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0011-0000-0000-000000000003', 'acc03b10-0000-0000-0000-000000000001', 'equation', '{"latex":"A = \\tfrac{1}{2}\\left|\\sum_i \\text{DMD}_i \\cdot \\text{Lat}_i\\right|,\\quad \\text{DMD}_i = \\text{DMD}_{i-1} + \\text{Dep}_{i-1} + \\text{Dep}_i","label":"Area by double meridian distance (DMD)","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0011-0000-0000-000000000004', 'acc03b10-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Units and conversions</h3><p>Computed areas come out in <strong>square feet</strong> (when coordinates are in feet) and are reported in <strong>acres</strong> for land: divide square feet by <strong>43,560</strong>. A legal description typically states the area as ''containing X acres, more or less.'' In Texas you may also meet historic units: an <strong>acre</strong> is about <strong>5,645.4 square varas</strong>, a <strong>labor</strong> is 1,000,000 square varas (&asymp; <strong>177.1 acres</strong>), and a <strong>league (sitio)</strong> is 25,000,000 square varas (&asymp; <strong>4,428.4 acres</strong>). When an old grant gives acreage in labors or leagues, convert with care, remembering historic varas varied slightly.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0011-0000-0000-000000000005', 'acc03b10-0000-0000-0000-000000000001', 'table', '{"headers":["Method","Formula","Notes"],"rows":[["Coordinate (shoelace)","A = (1/2)|sum(x_i*y_{i+1} - x_{i+1}*y_i)|","Modern default; needs coordinates"],["DMD","A = (1/2)|sum(DMD_i * Lat_i)|","Classical; from lat/dep directly"],["Acre conversion","acres = sq ft / 43,560","Reporting unit for land"],["Texas (vara) area","1 acre ~ 5,645.4 sq varas","1 labor ~ 177.1 ac; 1 league ~ 4,428.4 ac"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0011-0000-0000-000000000006', 'acc03b10-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"The two methods are identical mathematics, just bookkeeping differences. Use the coordinate method when you already have coordinates; use DMD when working straight from a balanced lat/dep table by hand."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0011-0000-0000-000000000007', 'acc03b10-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas context: report area consistent with the controlling description and the original grant. Quantity/area is the LOWEST-dignity call in Texas boundary law (after natural and artificial monuments, adjoinder, course, and distance), so a computed acreage never overrides a found monument (Stafford v. King, 30 Tex. 257)."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0011-0000-0000-000000000008', 'acc03b10-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Area by the coordinate (shoelace) method on a balanced traverse."}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0011-0000-0000-000000000009', 'acc03b10-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Coordinate (shoelace) area: A = (1/2)|sum(x_i*y_{i+1} - x_{i+1}*y_i)| on balanced coordinates.","DMD area: A = (1/2)|sum(DMD_i * Lat_i)|; DMD accumulates departures; same result.","Balance the traverse first; an unclosed figure gives a wrong area.","acres = sq ft / 43,560; in Texas 1 acre ~ 5,645.4 sq varas, 1 labor ~ 177.1 acres.","Area is the lowest-dignity call and never overrides a found monument."]}'::jsonb, 9);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0012-0000-0000-000000000000', 'acc03b11-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Boundaries are an evidence problem</h3><p>Determining a boundary is not the same as computing a traverse. The traverse gives precise measurements; the <strong>boundary</strong> is where the law &mdash; through the original grant, the monuments, and the evidence on the ground &mdash; says the line actually is. The surveyor''s task in retracement is to gather and weigh <strong>evidence</strong>: original and later monuments, recorded descriptions, occupation, and measurements, then locate the line consistent with the controlling intent. Precise measurement of the wrong point is worthless; the highest skill is reading the evidence correctly.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0012-0000-0000-000000000001', 'acc03b11-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Monuments: natural and artificial</h3><p>A <strong>monument</strong> is a physical object that marks a corner or line. <strong>Natural monuments</strong> are features that exist independent of the survey &mdash; rivers, creeks, lakes, prominent rocks, ridges &mdash; and are the most reliable evidence because they are large, durable, and hard to mistake. <strong>Artificial monuments</strong> are objects placed by people to mark the survey &mdash; set iron rods, pipes, marked (bearing) trees, stone mounds, fences called for in the description. A monument that can be <strong>identified as original</strong> (the very object the original surveyor set or called for) is powerful evidence: it shows where the line was actually run, which is the controlling question.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0012-0000-0000-000000000002', 'acc03b11-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Dignity of calls</h3><p>When the calls in a description conflict, they are ranked by reliability, the <strong>dignity of calls</strong>, highest to lowest: (1) <strong>natural monuments</strong>; (2) <strong>artificial monuments</strong>; (3) <strong>adjoinder</strong> (an adjacent, already-established line); (4) <strong>course</strong> (direction); (5) <strong>distance</strong>; (6) <strong>quantity/area</strong>. This is the foundational construction rule from <em>Stafford v. King</em>, 30 Tex. 257 (1867), which collapsed it to ''natural objects, artificial objects, then course and distance,'' later refined by treatises. The hierarchy is a set of <strong>rebuttable presumptions</strong>: a higher-dignity call ordinarily controls a lower one, so a found original monument controls over a conflicting bearing or distance.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0012-0000-0000-000000000003', 'acc03b11-0000-0000-0000-000000000001', 'table', '{"headers":["Rank","Call type","Examples"],"rows":[["1 (highest)","Natural monument","River, creek, lake, rock, ridge"],["2","Artificial monument","Iron rod, pipe, bearing tree, mound, called fence"],["3","Adjoinder","Adjacent established survey line"],["4","Course (direction)","Bearing / azimuth"],["5","Distance","Length of a call"],["6 (lowest)","Quantity / area","Acreage ''more or less''"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0012-0000-0000-000000000004', 'acc03b11-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Original vs. obliterated vs. lost: an ORIGINAL monument still in place controls; an OBLITERATED corner can be recovered from collateral evidence (witnesses, fences, ties) and still controls; only a truly LOST corner, unrecoverable by any evidence, is re-set by proportioning."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0012-0000-0000-000000000005', 'acc03b11-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas context: the dignity-of-calls hierarchy is only a rule of construction. It always yields to (i) the intent of the parties on the face of the grant and (ii) the footsteps of the original surveyor, located where the lines were actually run (Stafford v. King, 30 Tex. 257). A lower-dignity call can prevail when the instrument and circumstances show that was the intent."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0012-0000-0000-000000000006', 'acc03b11-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Dignity of calls, from natural monuments down to quantity."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0012-0000-0000-000000000007', 'acc03b11-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Boundary location weighs evidence: monuments, records, occupation, and measurements.","Dignity of calls: natural > artificial > adjoinder > course > distance > quantity/area.","A found, identified original monument controls over conflicting course-and-distance calls.","Original monuments control; obliterated corners are recovered from collateral evidence; only truly lost corners are proportioned.","All calls yield to intent and the original surveyor''s footsteps (Stafford v. King)."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0013-0000-0000-000000000000', 'acc03b12-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Retracement is following footsteps</h3><p>A <strong>resurvey is a retracement</strong>, not a fresh survey. It does not create or relocate boundaries; it re-establishes the lines and corners of the <strong>original</strong> survey. The cardinal Texas rule is to <strong>follow the footsteps of the original surveyor</strong>: locate the lines where they were actually run, as shown by the monuments and best evidence, even when later, more precise measurements disagree with the original field-note calls. The retracing surveyor''s job is to find what the original surveyor did, not to improve on it. This doctrine runs straight from <em>Stafford v. King</em> through modern Texas cases.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0013-0000-0000-000000000001', 'acc03b12-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Senior and junior rights</h3><p>When a grantor conveys parcels <strong>sequentially</strong> (one after another over time), the earlier <strong>senior</strong> conveyance takes the full measure of its description; the later <strong>junior</strong> conveyance takes only the <strong>remainder</strong>. A grantor cannot convey land already conveyed to a senior grantee, so any overlap or gap is resolved in the senior''s favor and the junior absorbs the <strong>excess or deficiency</strong>. Seniority does <em>not</em> enlarge a grant beyond its own description &mdash; it only governs conflicts. The Texas GLO patent system fits this naturally: the original patent is senior to later subdivisions carved from it.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0013-0000-0000-000000000002', 'acc03b12-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Simultaneous conveyances and proportioning</h3><p>By contrast, lots created <strong>simultaneously</strong> &mdash; classically, all lots on a recorded subdivision plat &mdash; are of <strong>equal dignity</strong>; no lot is senior. When the measured distance between two controlling, undisputed monuments differs from the record (platted) distance, the <strong>excess or deficiency is apportioned proportionately</strong> among the interior lots in proportion to their record lengths; no single lot absorbs the whole error. But apportionment is a <strong>last resort</strong>: found original monuments and recoverable (obliterated) corners control first. Proportioning applies only where a corner is genuinely <strong>lost</strong>, and only to ordinary distributed error &mdash; an isolable gross blunder is placed where it belongs.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0013-0000-0000-000000000003', 'acc03b12-0000-0000-0000-000000000001', 'equation', '{"latex":"\\text{corrected interval} = \\text{record interval} \\times \\frac{\\text{measured total}}{\\text{record total}}","label":"Single proportionate measurement (simultaneous lots)","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0013-0000-0000-000000000004', 'acc03b12-0000-0000-0000-000000000001', 'table', '{"headers":["Creation","Example","Conflict rule"],"rows":[["Sequential","Metes-and-bounds carve-outs over time","Senior/junior: senior whole, junior takes remainder"],["Simultaneous","Lots on one recorded plat","Apportion excess/deficiency proportionately"],["Lost corner","No monument, no collateral evidence","Proportionate measurement (last resort)"],["Found / obliterated","Monument in place or recoverable","Controls over proportioning"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0013-0000-0000-000000000005', 'acc03b12-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Occupation and acquiescence: long-standing occupation lines (fences, use) are evidence of where the original line was, and Texas applies agreed-boundary and acquiescence doctrines narrowly. They inform, but do not automatically override, the record and monuments."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0013-0000-0000-000000000006', 'acc03b12-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas context: there is NO controlling Texas Supreme Court case adopting ''single/double proportionate measurement'' by name; in Texas, proportioning is established surveying practice used sparingly, and original-survey footsteps dominate because Texas land descends from GLO original surveys, not a federal PLSS grid. Honor junior/senior rights and the record chain (TBPELS 22 TAC ch. 138)."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0013-0000-0000-000000000007', 'acc03b12-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["A resurvey retraces; the original surveyor''s footsteps control over inconsistent field-note calls.","Sequential conveyances: senior takes its full description, junior absorbs excess/deficiency.","Simultaneous (platted) lots: apportion excess/deficiency proportionately; none is senior.","Proportioning is a last resort for genuinely lost corners only.","In Texas, footsteps and the GLO original survey dominate; proportioning is used sparingly."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0014-0000-0000-000000000000', 'acc03b13-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Subdivision concepts</h3><p>A <strong>subdivision</strong> divides a parent tract into <strong>lots</strong> for sale or development, recorded on a <strong>plat</strong>. The plat organizes land into <strong>blocks</strong> (groups of lots) separated by <strong>streets / rights-of-way</strong>, and dedicates <strong>easements</strong> (utility, drainage, access) as shown. Because all lots are created by the single recorded instrument, they are a <strong>simultaneous conveyance</strong> of equal dignity &mdash; the seniority and apportionment rules from retracement apply directly. Lot lines are described relative to the block and the platted monuments; the plat''s recorded dimensions, bearings, and curve data govern, subject always to found monuments controlling over measurement.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0014-0000-0000-000000000001', 'acc03b13-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Horizontal circular curves</h3><p>Street and roadway alignments turn with <strong>horizontal circular curves</strong>, and lots fronting them have <strong>curved boundaries</strong> described by curve data. A simple circular curve is defined by its <strong>radius R</strong> and its <strong>central (deflection) angle &Delta;</strong> &mdash; the angle the alignment turns through. From these two values every other element follows. The <strong>point of curvature (PC)</strong> is where the tangent meets the curve; the <strong>point of tangency (PT)</strong> is where the curve rejoins the tangent; the <strong>point of intersection (PI)</strong> is where the two tangents would meet.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0014-0000-0000-000000000002', 'acc03b13-0000-0000-0000-000000000001', 'equation', '{"latex":"T = R\\tan\\!\\left(\\tfrac{\\Delta}{2}\\right), \\quad L = R\\,\\Delta_{\\text{rad}} = \\frac{R\\,\\Delta\\,\\pi}{180}, \\quad C = 2R\\sin\\!\\left(\\tfrac{\\Delta}{2}\\right)","label":"Curve tangent T, arc length L, and long chord C","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0014-0000-0000-000000000003', 'acc03b13-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The curve elements</h3><p>The principal elements are: the <strong>tangent distance T</strong> = R&middot;tan(&Delta;/2), the distance from PC (or PT) back to the PI; the <strong>curve (arc) length L</strong> = R&middot;&Delta; in radians = R&middot;&Delta;&middot;&pi;/180, the length measured along the arc; the <strong>long chord C</strong> = 2R&middot;sin(&Delta;/2), the straight-line distance from PC to PT; the <strong>external distance E</strong> and <strong>middle ordinate M</strong>, which describe how far the curve stands from the PI and the chord. The <strong>degree of curve</strong> (arc or chord definition) is the central angle subtending a standard 100-ft arc or chord and is an alternative way to specify sharpness. A plat note for curved frontage typically lists R, &Delta;, L, and the chord bearing and length.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0014-0000-0000-000000000004', 'acc03b13-0000-0000-0000-000000000001', 'table', '{"headers":["Element","Symbol","Formula"],"rows":[["Radius","R","Given / design"],["Central angle","delta","Given (deflection of tangents)"],["Tangent distance","T","R * tan(delta/2)"],["Arc (curve) length","L","R * delta * PI / 180"],["Long chord","C","2 * R * sin(delta/2)"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0014-0000-0000-000000000005', 'acc03b13-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Degrees vs. radians: arc length needs the central angle in RADIANS (multiply degrees by PI/180), while T and C use the half-angle in the trig functions. Mixing the two is the most common curve-computation error."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0014-0000-0000-000000000006', 'acc03b13-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas context: subdivision platting in Texas is governed by Tex. Local Government Code ch. 212 (municipal) and ch. 232 (county). Plats must meet local and state platting requirements before recording, and a recorded plat creates the lots simultaneously, fixing equal-dignity lot lines and dedicated rights-of-way and easements."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0014-0000-0000-000000000007', 'acc03b13-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Elements of a simple horizontal circular curve."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0014-0000-0000-000000000008', 'acc03b13-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["A subdivision plat creates equal-dignity lots simultaneously, with blocks, rights-of-way, and dedicated easements.","Tangent T = R*tan(delta/2); arc length L = R*delta*PI/180; long chord C = 2*R*sin(delta/2).","Arc length needs delta in radians; T and C use the half-angle.","Curved lot frontage is described by R, delta, arc length, and chord bearing/length.","Texas platting follows Local Government Code ch. 212/232."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0015-0000-0000-000000000000', 'acc03b14-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Software in the traverse workflow</h3><p>Every step you have computed by hand is automated in <strong>survey software</strong> and data collectors: resolving courses into latitudes and departures, summing the <strong>misclosure</strong>, reporting the <strong>ratio of closure</strong>, applying an <strong>adjustment</strong> (compass, transit, Crandall, or least squares), accumulating <strong>coordinates</strong>, and computing <strong>area</strong>. Packages such as spreadsheets for the compass rule, and dedicated COGO/least-squares programs, turn hours of tabulation into seconds. The catch is unchanged: software computes exactly what you tell it, so <strong>correct input</strong> &mdash; right bearings, horizontal distances, consistent units, the proper datum and zone &mdash; is everything.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0015-0000-0000-000000000001', 'acc03b14-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Compass-rule spreadsheets vs. least squares</h3><p>Two tiers of tools coexist. A <strong>compass-rule spreadsheet</strong> mirrors the hand method: enter bearings and distances, and it returns lat/dep, misclosure, ratio, corrections, coordinates, and area. It is transparent and fine for ordinary closed-loop boundary traverses. <strong>Least-squares software</strong> is more rigorous: it accepts redundant observations (angles, distances, GNSS vectors), weights each by its estimated precision, and produces the statistically best coordinates along with <strong>error ellipses</strong> and statistics (standard deviations, residuals, a chi-square test). For networks, control, and any work mixing measurement types, least squares is the professional standard; the compass rule remains the everyday tool for a simple loop.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0015-0000-0000-000000000002', 'acc03b14-0000-0000-0000-000000000001', 'table', '{"headers":["Capability","Compass-rule spreadsheet","Least-squares software"],"rows":[["Input","Single loop of courses","Redundant, mixed observations"],["Weighting","By course length","By observation precision (rigorous)"],["Output","Coordinates, area, ratio","Coordinates + error ellipses + statistics"],["Best for","Simple boundary loop","Networks, control, GNSS-integrated work"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0015-0000-0000-000000000003', 'acc03b14-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Garbage in, garbage out: software cannot detect a transposed digit, a slope distance entered as horizontal, or a wrong zone. Range-check inputs and confirm units and datum before trusting any output."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0015-0000-0000-000000000004', 'acc03b14-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Verifying the output</h3><p>Professional practice never trusts software blindly. <strong>Verify</strong> with independent checks: <strong>inverse</strong> between adjusted stations and compare to the field-measured courses; confirm the <strong>ratio of closure</strong> is plausible for the instrument and method; sanity-check the <strong>area</strong> against a rough hand estimate; and make sure coordinates are <strong>monotonic and reasonable</strong>. Confirm whether the program worked in <strong>grid or ground</strong> and on which <strong>datum/zone</strong>. Finally, <strong>document</strong> the software, version, adjustment method, settings, and basis of bearings &mdash; the record that lets another professional reproduce and defend the result.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0015-0000-0000-000000000005', 'acc03b14-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas context: regardless of the software used, the survey must meet TBPELS standards of practice (22 TAC ch. 138) and clearly state the basis of bearings, datum (typically NAD83 Texas State Plane), and whether distances are grid or ground. The licensed surveyor remains responsible for the result, not the software."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0015-0000-0000-000000000006', 'acc03b14-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Software automates lat/dep, misclosure, ratio, adjustment, coordinates, and area, but depends on correct input.","Compass-rule spreadsheets suit a simple loop; least squares handles redundant, mixed observations rigorously.","Least squares reports error ellipses and statistics describing positional uncertainty.","Always verify output (inverse, closure, area sanity) and confirm grid vs. ground and datum.","The licensed surveyor, not the software, is responsible under TBPELS standards."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0016-0000-0000-000000000000', 'acc03b15-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Texas professional standards</h3><p>Land surveying in Texas is a <strong>licensed profession</strong> regulated by the <strong>Texas Board of Professional Engineers and Land Surveyors (TBPELS)</strong> under the Professional Land Surveying Practices Act, <strong>Tex. Occ. Code ch. 1071</strong>. The Board''s rules live in <strong>22 Texas Administrative Code, Title 22, Part 6</strong>, with the surveyor standards of practice and professional conduct in <strong>ch. 138</strong>. These standards govern who may practice, the categories and required accuracies of surveys, the contents of a survey and plat, the basis of bearings and datum, recordkeeping, and ethical duties. A survey that does not meet the applicable category''s standards is professionally deficient regardless of how precise its arithmetic looks.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0016-0000-0000-000000000001', 'acc03b15-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Tying the course together</h3><p>SRVY 1341 is one connected story. You learned to <strong>measure</strong> distances (with tape corrections) and directions (compass, declination, angle types); to <strong>set up and care for instruments</strong>; to resolve courses into <strong>latitudes and departures</strong>, quantify <strong>misclosure</strong> and the <strong>ratio of closure</strong>, and <strong>adjust</strong> by the compass or transit rule; to apply <strong>coordinate geometry</strong> (inverse, intersections) and compute <strong>area</strong> (coordinate and DMD methods); and finally to <strong>determine boundaries</strong> from evidence using the dignity of calls and the footsteps doctrine, including subdivision and curve concepts. Each topic feeds the next: good measurement enables a tight traverse, a closed traverse yields trustworthy coordinates and area, and sound evidence analysis turns those numbers into a defensible boundary.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0016-0000-0000-000000000002', 'acc03b15-0000-0000-0000-000000000001', 'table', '{"headers":["Stage","Weeks","Core skill"],"rows":[["Measure","1-6","Distance, direction, angles, instrument setup"],["Check & adjust","7","Lat/dep, misclosure, ratio, compass & transit"],["Compute","9,10,14","Inverse, intersections, area, software"],["Determine boundary","11-13","Evidence, dignity of calls, footsteps, subdivision & curves"],["Practice professionally","15","TBPELS standards, records, basis of bearings"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0016-0000-0000-000000000003', 'acc03b15-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Final-exam focus: be able to run a full closed traverse end to end and to reason about a boundary-evidence scenario using the dignity of calls and footsteps doctrine. Those two abilities span most of the course."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0016-0000-0000-000000000004', 'acc03b15-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas context: remember the Texas distinctives throughout - the GLO original-survey, metes-and-bounds system (no PLSS grid); varas in historic records; the dignity-of-calls hierarchy from Stafford v. King; footsteps over recomputed measurement; and TBPELS regulation under Tex. Occ. Code ch. 1071 and 22 TAC ch. 138."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0016-0000-0000-000000000005', 'acc03b15-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Texas surveying is regulated by TBPELS (Tex. Occ. Code ch. 1071; 22 TAC ch. 138).","Course arc: measure -> check/adjust -> compute -> determine the boundary.","Boundary location follows intent, monuments, and the original surveyor''s footsteps.","Professional duties: accuracy standards, records, basis of bearings, continuing competence.","For the final, master the full closed-traverse computation and boundary-evidence reasoning."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0017-0000-0000-000000000000', 'acc03b16-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Scope of the final</h3><p>The final exam is <strong>comprehensive</strong>, spanning the whole course. Computationally, expect a full <strong>closed-traverse</strong> problem (latitudes and departures, misclosure, ratio of closure, compass/transit adjustment, coordinates, and area), plus <strong>coordinate geometry</strong> (inverse and intersections), <strong>area</strong> by coordinate and DMD methods, and <strong>curve</strong> elements (T, L, C from R and &Delta;). Conceptually, expect <strong>boundary-determination</strong> questions: dignity of calls, original vs. lost corners, senior/junior rights, the footsteps doctrine, subdivision concepts, and Texas professional standards.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0017-0000-0000-000000000001', 'acc03b16-0000-0000-0000-000000000001', 'text', '{"html":"<h3>How to perform</h3><p>Bring the disciplined habits the course built. For every computation, <strong>write the formula</strong>, substitute with <strong>units</strong>, evaluate, and run the built-in <strong>check</strong> (hypot recombination for a course, sums-to-zero for an adjusted traverse, inverse to verify a course, a rough area estimate). For boundary-reasoning questions, anchor your answer in the <strong>controlling principle</strong>: intent first, then the dignity of calls, then the footsteps of the original surveyor &mdash; and flag the Texas distinctives (GLO/metes-and-bounds, no PLSS, varas, <em>Stafford v. King</em>). Manage time: secure the parts you know, show steps for partial credit, and do not let one hard item consume the hour.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0017-0000-0000-000000000002', 'acc03b16-0000-0000-0000-000000000001', 'table', '{"headers":["Problem type","What to show"],"rows":[["Closed traverse","Lat/dep, misclosure, ratio, adjustment, coordinates, area"],["Inverse / intersection","dN, dE, hypot, atan2; constraint geometry"],["Area","Shoelace or DMD on balanced coordinates; acres"],["Curve","T = R tan(delta/2), L = R*delta*PI/180, C = 2R sin(delta/2)"],["Boundary evidence","Intent, dignity of calls, footsteps"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0017-0000-0000-000000000003', 'acc03b16-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"One-line reminders: azimuth uses atan2(dE, dN); arc length uses delta in radians; balance before computing area; a found original monument outranks course and distance."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0017-0000-0000-000000000004', 'acc03b16-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas context: keep the Texas framework in mind on conceptual items - dignity of calls and footsteps from Stafford v. King, GLO metes-and-bounds (no PLSS), historic varas, and TBPELS regulation (Tex. Occ. Code ch. 1071; 22 TAC ch. 138)."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3110-0017-0000-0000-000000000005', 'acc03b16-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["The final is comprehensive across measurement, adjustment, COGO, area, curves, and boundary determination.","Run a complete closed traverse and verify with built-in checks.","Solve inverse, intersection, and curve problems with correct units.","Answer boundary questions by intent, dignity of calls, and footsteps, flagging Texas distinctives."]}'::jsonb, 5);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000001', 'Traverse', 'A connected series of measured lines (courses), each with a length and a direction, used to locate points and compute their coordinates.', 'Lengths + directions of connected lines.', 'acc00003-0000-0000-0000-000000000003', 'acc03b00-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000002', 'TBPELS', 'The Texas Board of Professional Engineers and Land Surveyors, the state agency that licenses and regulates surveyors (and engineers) under Tex. Occ. Code ch. 1071.', 'Texas licensing/regulatory board.', 'acc00003-0000-0000-0000-000000000003', 'acc03b00-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000003', 'General Land Office (GLO)', 'The Texas state agency that holds original land-grant records and issues patents; the source of Texas''s original-survey, metes-and-bounds title system.', 'Texas sovereign-land archive and patents.', 'acc00003-0000-0000-0000-000000000003', 'acc03b00-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000004', 'Tape (chaining) correction', 'A systematic adjustment applied to a measured taped distance to account for standardization, temperature, tension, sag, or slope.', 'Removes systematic taping error.', 'acc00003-0000-0000-0000-000000000003', 'acc03b01-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000005', 'Temperature correction (taping)', 'The change in a steel tape''s length due to thermal expansion, C_t = alpha*(T - T0)*L, with alpha = 0.00000645 per deg F.', 'alpha*(T - T0)*L.', 'acc00003-0000-0000-0000-000000000003', 'acc03b01-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000006', 'Sag correction', 'The always-negative correction for a tape hanging in a catenary between end supports, which makes the tape read longer than the true chord.', 'Tape reads long; correction negative.', 'acc00003-0000-0000-0000-000000000003', 'acc03b01-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000007', 'Vara', 'A Texas surveying unit equal to 33 1/3 inches (2.7778 ft); 36 varas equal exactly 100 feet and appear throughout GLO grant records.', '33 1/3 in; 36 varas = 100 ft.', 'acc00003-0000-0000-0000-000000000003', 'acc03b01-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000008', 'Bearing', 'A direction expressed as a quadrant letter, an acute angle (0-90 deg) from the meridian, and a second letter, e.g. N 42 deg 15'' E.', 'Quadrant + acute angle + quadrant.', 'acc00003-0000-0000-0000-000000000003', 'acc03b02-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000009', 'Azimuth', 'A direction measured clockwise from a reference meridian (usually north), ranging 0 to 360 degrees.', 'Clockwise from north, 0-360.', 'acc00003-0000-0000-0000-000000000003', 'acc03b02-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000010', 'DMS to DD conversion', 'Converting degrees-minutes-seconds to decimal degrees by DD = D + M/60 + S/3600.', 'Add M/60 and S/3600.', 'acc00003-0000-0000-0000-000000000003', 'acc03b02-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000011', 'Back bearing', 'The bearing of a line viewed from the opposite end; the angle stays the same and both quadrant letters reverse.', 'Swap both N/S and E/W letters.', 'acc00003-0000-0000-0000-000000000003', 'acc03b02-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000012', 'Magnetic declination', 'The horizontal angle between magnetic north and true (geodetic) north; east when magnetic north is east of true north, west otherwise.', 'Angle from magnetic north to true north.', 'acc00003-0000-0000-0000-000000000003', 'acc03b03-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000013', 'Secular variation', 'The slow change in magnetic declination over time at a given location, important when retracing old magnetic-bearing surveys.', 'Declination drifts year to year.', 'acc00003-0000-0000-0000-000000000003', 'acc03b03-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000014', 'Field notes', 'The contemporaneous, legible, never-erased written record of survey observations, made in ink or a controlled collector and admissible as evidence.', 'Permanent legal record of observations.', 'acc00003-0000-0000-0000-000000000003', 'acc03b03-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000015', 'Standards (of an instrument)', 'The two upright supports that carry the telescope''s horizontal axis; an instrument should be lifted by the standards, never the telescope.', 'The uprights; lift here.', 'acc00003-0000-0000-0000-000000000003', 'acc03b04-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000016', 'Collimation check', 'A field procedure that detects line-of-sight (and vertical-index) error by observing on both faces; corrected so the line of sight is truly perpendicular to the axes.', 'Both-face check of line of sight.', 'acc00003-0000-0000-0000-000000000003', 'acc03b04-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000017', 'Instrument calibration record', 'Documentation that an instrument was checked against traceable standards on a schedule, supporting the accuracy and defensibility of survey data.', 'Proof the instrument was in tolerance.', 'acc00003-0000-0000-0000-000000000003', 'acc03b04-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000018', 'Optical / laser plummet', 'The downward-pointing sight or laser used to center the instrument''s vertical axis exactly over a ground mark.', 'Centers instrument over the point.', 'acc00003-0000-0000-0000-000000000003', 'acc03b05-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000019', 'Plate level (fine leveling)', 'The sensitive tubular or electronic level used with the three leveling screws to make the instrument''s vertical axis truly vertical.', 'Sensitive level for fine leveling.', 'acc00003-0000-0000-0000-000000000003', 'acc03b05-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000020', 'Centering (setup) error', 'The horizontal offset of the instrument from the true mark, which produces an angular error approximately equal to the offset divided by the sight distance.', 'Off-mark error; worst on short sights.', 'acc00003-0000-0000-0000-000000000003', 'acc03b05-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000021', 'Height of instrument (HI)', 'The vertical distance from the occupied ground mark up to the instrument''s trunnion axis, used in trigonometric leveling and 3D reductions.', 'Ground mark to trunnion axis.', 'acc00003-0000-0000-0000-000000000003', 'acc03b05-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000022', 'Interior angle', 'An angle measured inside a closed polygon at a station; the interior angles of an n-sided closed traverse sum to (n-2)*180 degrees.', 'Inside the polygon; sum (n-2)*180.', 'acc00003-0000-0000-0000-000000000003', 'acc03b06-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000023', 'Deflection angle', 'The angle turned right or left from the prolongation of the preceding course; deflection angles of a closed loop algebraically sum to 360 degrees.', 'From straight-ahead; sum 360.', 'acc00003-0000-0000-0000-000000000003', 'acc03b06-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000024', 'Angle to the right', 'The clockwise angle measured from the backsight to the foresight, the standard convention for modern total-station traverses.', 'Clockwise BS to FS.', 'acc00003-0000-0000-0000-000000000003', 'acc03b06-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000025', 'Angular closure (loop)', 'The difference between the measured sum of interior angles and (n-2)*180 degrees, distributed among the angles before computing azimuths.', 'Measured sum vs (n-2)*180.', 'acc00003-0000-0000-0000-000000000003', 'acc03b06-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000026', 'Latitude and departure', 'The north-south component (Lat = d cos bearing) and east-west component (Dep = d sin bearing) of a course.', 'N-S = d cos; E-W = d sin.', 'acc00003-0000-0000-0000-000000000003', 'acc03b07-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000027', 'Compass (Bowditch) rule', 'An adjustment distributing latitude and departure misclosure in proportion to course length, assuming comparable angle and distance precision.', 'Correction proportional to length.', 'acc00003-0000-0000-0000-000000000003', 'acc03b07-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000028', 'Transit rule', 'An adjustment distributing misclosure in proportion to each course''s |latitude| and |departure|, assuming angles are more precise than distances.', 'Weight by |Lat|, |Dep|.', 'acc00003-0000-0000-0000-000000000003', 'acc03b07-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000029', 'Least-squares adjustment', 'A rigorous adjustment that weights every observation by its estimated precision, producing the statistically best coordinates and error ellipses.', 'Inverse-variance weighting; rigorous.', 'acc00003-0000-0000-0000-000000000003', 'acc03b07-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000030', 'Short-traverse workflow', 'The exam-critical sequence: resolve courses into lat/dep, sum for misclosure, compute ratio of closure, then adjust by compass or transit rule.', 'Lat/dep -> misclosure -> ratio -> adjust.', 'acc00003-0000-0000-0000-000000000003', 'acc03b08-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000031', 'Ratio of closure', 'Perimeter divided by linear misclosure, reported as 1:N with N = round(perimeter / misclosure); larger N is better.', '1 : (P / E).', 'acc00003-0000-0000-0000-000000000003', 'acc03b08-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000032', 'Inverse (COGO)', 'Computing the distance and azimuth between two coordinated points: distance = hypot(dE, dN), azimuth = atan2(dE, dN).', 'Coordinates -> distance and direction.', 'acc00003-0000-0000-0000-000000000003', 'acc03b09-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000033', 'atan2 for azimuth', 'The two-argument arctangent that returns an azimuth from north as atan2(departure, latitude) = atan2(dE, dN), quadrant-correct over 0-360.', 'atan2(dE, dN) gives azimuth.', 'acc00003-0000-0000-0000-000000000003', 'acc03b09-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000034', 'Bearing-bearing intersection', 'Locating a point as the crossing of two lines of known direction emanating from two known points.', 'Two directions cross at a point.', 'acc00003-0000-0000-0000-000000000003', 'acc03b09-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000035', 'Trilateration (distance-distance)', 'Locating a point from two known distances to two known points; geometrically the intersection of two circles.', 'Two distances locate a point.', 'acc00003-0000-0000-0000-000000000003', 'acc03b09-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000036', 'Coordinate (shoelace) area', 'Area of a closed polygon as half the absolute value of the sum of cross-products x_i*y_{i+1} - x_{i+1}*y_i, using balanced coordinates in perimeter order.', 'Half the absolute cross-product sum.', 'acc00003-0000-0000-0000-000000000003', 'acc03b10-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000037', 'Double meridian distance (DMD)', 'A classical area method where DMD_i = DMD_{i-1} + Dep_{i-1} + Dep_i and area = (1/2)|sum(DMD_i * Lat_i)|.', 'Accumulated departures times latitudes.', 'acc00003-0000-0000-0000-000000000003', 'acc03b10-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000038', 'Acre', 'A unit of land area equal to 43,560 square feet (about 5,645.4 square varas in Texas).', '43,560 sq ft.', 'acc00003-0000-0000-0000-000000000003', 'acc03b10-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000039', 'Labor (area)', 'A Texas land-area unit of 1,000,000 square varas, approximately 177.1 acres.', '1,000,000 sq varas ~ 177.1 ac.', 'acc00003-0000-0000-0000-000000000003', 'acc03b10-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000040', 'Monument (boundary)', 'A physical object that marks a corner or line; natural monuments (rivers, rocks) outrank artificial ones (iron rods, bearing trees).', 'Physical marker of a corner/line.', 'acc00003-0000-0000-0000-000000000003', 'acc03b11-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000041', 'Dignity of calls', 'The reliability hierarchy for conflicting description calls: natural monument > artificial monument > adjoinder > course > distance > quantity.', 'Natural > artificial > course > distance.', 'acc00003-0000-0000-0000-000000000003', 'acc03b11-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000042', 'Stafford v. King', 'The foundational 1867 Texas case (30 Tex. 257) establishing the dignity-of-calls hierarchy and the footsteps-of-the-original-surveyor doctrine.', 'Texas dignity-of-calls + footsteps.', 'acc00003-0000-0000-0000-000000000003', 'acc03b11-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000043', 'Lost vs. obliterated corner', 'An obliterated corner can be recovered from collateral evidence and still controls; only a truly lost corner, unrecoverable by evidence, is re-set by proportioning.', 'Obliterated is recoverable; lost is proportioned.', 'acc00003-0000-0000-0000-000000000003', 'acc03b11-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000044', 'Footsteps doctrine', 'The Texas retracement rule that a resurvey re-establishes the original survey, following where the original surveyor actually ran the lines even against later measurements.', 'Follow the original surveyor''s footsteps.', 'acc00003-0000-0000-0000-000000000003', 'acc03b12-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000045', 'Senior / junior rights', 'When parcels are conveyed sequentially, the senior conveyance takes its full description and the junior takes only the remainder, absorbing excess or deficiency.', 'Senior whole; junior takes remainder.', 'acc00003-0000-0000-0000-000000000003', 'acc03b12-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000046', 'Proportionate measurement', 'Distributing excess or deficiency among simultaneously created lots in proportion to their record lengths; a last resort used only for genuinely lost corners.', 'Distribute error by record length; last resort.', 'acc00003-0000-0000-0000-000000000003', 'acc03b12-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000047', 'Simultaneous vs. sequential conveyance', 'Simultaneous (platted) lots share equal dignity and are apportioned; sequential carve-outs follow senior/junior rights.', 'Plat = apportion; carve-out = senior/junior.', 'acc00003-0000-0000-0000-000000000003', 'acc03b12-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000048', 'Subdivision plat', 'A recorded instrument dividing a parent tract into blocks and lots, dedicating streets/rights-of-way and easements, and creating all lots simultaneously.', 'Recorded division into lots and ROW.', 'acc00003-0000-0000-0000-000000000003', 'acc03b13-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000049', 'Tangent distance (T)', 'The distance from the point of curvature (or tangency) to the point of intersection of a horizontal curve, T = R*tan(delta/2).', 'R * tan(delta/2).', 'acc00003-0000-0000-0000-000000000003', 'acc03b13-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000050', 'Curve (arc) length (L)', 'The length measured along a circular curve''s arc, L = R*delta with delta in radians = R*delta*PI/180.', 'R * delta (radians).', 'acc00003-0000-0000-0000-000000000003', 'acc03b13-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000051', 'Long chord (C)', 'The straight-line distance from the point of curvature to the point of tangency of a circular curve, C = 2*R*sin(delta/2).', '2 * R * sin(delta/2).', 'acc00003-0000-0000-0000-000000000003', 'acc03b13-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000052', 'COGO software', 'Coordinate-geometry and survey software that automates traverse computation, adjustment, coordinates, and area from input courses or coordinates.', 'Automates traverse computation.', 'acc00003-0000-0000-0000-000000000003', 'acc03b14-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000053', 'Least-squares software', 'Programs that weight redundant observations by precision to produce optimal coordinates plus error ellipses and statistics.', 'Rigorous, weighted, redundant adjustment.', 'acc00003-0000-0000-0000-000000000003', 'acc03b14-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000054', 'Error ellipse', 'A graphical statistical region from a least-squares adjustment showing the positional uncertainty of a computed station.', 'Shows positional uncertainty.', 'acc00003-0000-0000-0000-000000000003', 'acc03b14-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000055', 'TBPELS standards of practice', 'The Texas surveyor rules in 22 TAC ch. 138 governing survey categories, required accuracies, plat contents, basis of bearings, records, and conduct.', '22 TAC ch. 138 surveyor rules.', 'acc00003-0000-0000-0000-000000000003', 'acc03b15-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000056', 'Professional Land Surveying Practices Act', 'Tex. Occ. Code ch. 1071, the Texas statute that establishes licensure and regulation of land surveyors under TBPELS.', 'Tex. Occ. Code ch. 1071.', 'acc00003-0000-0000-0000-000000000003', 'acc03b15-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000057', 'Basis of bearings', 'The reference (e.g., Texas State Plane NAD83, a record line, or astronomic north) to which all directions on a survey are referred, stated on the plat.', 'Stated reference for all directions.', 'acc00003-0000-0000-0000-000000000003', 'acc03b15-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000058', 'Comprehensive traverse workflow', 'The full sequence tested on the final: lat/dep, misclosure, ratio of closure, adjustment, coordinates, and area.', 'Lat/dep -> ... -> coordinates -> area.', 'acc00003-0000-0000-0000-000000000003', 'acc03b16-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3140-0000-0000-0000-000000000059', 'Boundary-reasoning anchor', 'On the exam, resolve boundary scenarios by intent first, then dignity of calls, then the footsteps of the original surveyor.', 'Intent -> dignity of calls -> footsteps.', 'acc00003-0000-0000-0000-000000000003', 'acc03b16-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-31']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000001', 'Which agency licenses and regulates professional land surveyors in Texas?', 'multiple_choice', '["The Texas Board of Professional Engineers and Land Surveyors (TBPELS)","The federal Bureau of Land Management (BLM)","The U.S. General Land Office","The National Geodetic Survey (NGS)"]'::jsonb, 'The Texas Board of Professional Engineers and Land Surveyors (TBPELS)', 'TBPELS, created in 2019 by merging the former engineering and surveying boards, licenses and regulates surveyors under Tex. Occ. Code ch. 1071. The BLM and federal GLO administer federal public lands (not Texas); the NGS maintains the national geodetic datum.', 'easy', 'acc00003-0000-0000-0000-000000000003', 'acc03b00-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000002', 'A 100.00 ft horizontal distance is measured along ground with a 5.00 ft elevation difference between the tape ends. The horizontal distance (ft) is closest to:', 'numeric_input', '[]'::jsonb, '99.87', 'H = sqrt(L^2 - h^2) = sqrt(100^2 - 5^2) = sqrt(10000 - 25) = sqrt(9975) = 99.87 ft. The horizontal distance is always shorter than the slope distance.', 'medium', 'acc00003-0000-0000-0000-000000000003', 'acc03b01-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000003', 'The temperature correction for a steel tape is given by which expression (alpha = coefficient of expansion, T0 = standard temperature, L = length)?', 'multiple_choice', '["alpha * (T - T0) * L","alpha * (T0 - T) / L","(T - T0) / (alpha * L)","alpha * L / (T - T0)"]'::jsonb, 'alpha * (T - T0) * L', 'Thermal expansion of a steel tape is C_t = alpha*(T - T0)*L. For steel alpha is about 0.00000645 per deg F. The other forms are dimensionally wrong.', 'medium', 'acc00003-0000-0000-0000-000000000003', 'acc03b01-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000004', 'Convert 42 deg 15'' 30" to decimal degrees (round to four decimals).', 'numeric_input', '[]'::jsonb, '42.2583', 'DD = 42 + 15/60 + 30/3600 = 42 + 0.2500 + 0.008333 = 42.2583 degrees.', 'easy', 'acc00003-0000-0000-0000-000000000003', 'acc03b02-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000005', 'The back bearing of a line whose bearing is N 42 deg 15'' E is:', 'multiple_choice', '["S 42 deg 15'' W","N 42 deg 15'' W","S 47 deg 45'' W","N 47 deg 45'' E"]'::jsonb, 'S 42 deg 15'' W', 'A back bearing keeps the same angle and reverses both quadrant letters: N..E becomes S..W. The angle (42 deg 15'') is unchanged.', 'medium', 'acc00003-0000-0000-0000-000000000003', 'acc03b02-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000006', 'Magnetic declination is the angle between:', 'multiple_choice', '["Magnetic north and true (geodetic) north","Grid north and true north","The compass needle and the line of sight","Two successive courses of a traverse"]'::jsonb, 'Magnetic north and true (geodetic) north', 'Declination is measured between where the compass points (magnetic north) and true/geodetic north. The angle between grid and true north is convergence; between courses is a deflection or interior angle.', 'easy', 'acc00003-0000-0000-0000-000000000003', 'acc03b03-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000007', 'A smartphone compass app is an acceptable instrument for recording final boundary bearings on a survey.', 'true_false', '["True","False"]'::jsonb, 'False', 'Phone magnetometers are easily disturbed by nearby steel and are only a few degrees accurate; they are reconnaissance aids, not survey-grade instruments. Boundary bearings come from a total station or GNSS.', 'easy', 'acc00003-0000-0000-0000-000000000003', 'acc03b03-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000008', 'During fine leveling, after centering the plate bubble using two leveling screws, you rotate the instrument 90 degrees and center the bubble using:', 'multiple_choice', '["Only the third screw","All three screws together","The same two screws again","The optical plummet"]'::jsonb, 'Only the third screw', 'The standard routine: two screws (turned in opposite directions) to center, rotate 90 degrees, then the third screw alone. The plummet centers over the point; it does not level.', 'medium', 'acc00003-0000-0000-0000-000000000003', 'acc03b05-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000009', 'The interior angles of a closed five-sided (n = 5) traverse should sum to:', 'numeric_input', '[]'::jsonb, '540', '(n - 2) * 180 = (5 - 2) * 180 = 3 * 180 = 540 degrees.', 'easy', 'acc00003-0000-0000-0000-000000000003', 'acc03b06-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000010', 'Observing each angle face-left and face-right (direct and reverse) primarily cancels which errors?', 'multiple_choice', '["Collimation and horizontal-axis (trunnion) errors","Centering and temperature errors","Earth-curvature and refraction errors","Tape sag and slope errors"]'::jsonb, 'Collimation and horizontal-axis (trunnion) errors', 'These instrumental errors reverse sign between the two faces, so averaging D&R removes them. Centering, atmospheric, and taping errors are unrelated to telescope face.', 'medium', 'acc00003-0000-0000-0000-000000000003', 'acc03b06-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000011', 'The transit rule distributes traverse misclosure in proportion to:', 'multiple_choice', '["The magnitude of each course''s latitude and departure","The length of each course","The square of each course''s length","The number of courses"]'::jsonb, 'The magnitude of each course''s latitude and departure', 'The transit rule weights corrections by |Lat| and |Dep| (assuming angles more precise than distances). Weighting by course length is the compass (Bowditch) rule.', 'medium', 'acc00003-0000-0000-0000-000000000003', 'acc03b07-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000012', 'A closed-loop traverse has sum of latitudes = +0.060 ft and sum of departures = -0.080 ft. The linear misclosure (ft) is:', 'numeric_input', '[]'::jsonb, '0.10', 'E = hypot(0.060, 0.080) = sqrt(0.060^2 + 0.080^2) = sqrt(0.0036 + 0.0064) = sqrt(0.0100) = 0.100 ft.', 'medium', 'acc00003-0000-0000-0000-000000000003', 'acc03b07-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000013', 'To compute the azimuth (from north) between two coordinated points, you use:', 'multiple_choice', '["atan2(dE, dN)","atan2(dN, dE)","atan(dN / dE)","acos(dN / distance) always"]'::jsonb, 'atan2(dE, dN)', 'Azimuth from north is atan2(departure, latitude) = atan2(dE, dN), which is quadrant-correct over 0-360. Swapping the arguments gives the angle from the east axis.', 'medium', 'acc00003-0000-0000-0000-000000000003', 'acc03b09-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000014', 'A balanced parcel computes to 130,680 square feet. Its area in acres is:', 'numeric_input', '[]'::jsonb, '3.00', '1 acre = 43,560 sq ft, so 130,680 / 43,560 = 3.00 acres.', 'easy', 'acc00003-0000-0000-0000-000000000003', 'acc03b10-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000015', 'Quantity (area) is the highest-dignity call, so a computed acreage overrides a found original monument.', 'true_false', '["True","False"]'::jsonb, 'False', 'Quantity/area is the LOWEST-dignity call. A found original monument (artificial) outranks course, distance, and quantity, so computed acreage never overrides it (Stafford v. King).', 'medium', 'acc00003-0000-0000-0000-000000000003', 'acc03b10-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000016', 'Under the Texas dignity of calls, which controls when calls conflict?', 'multiple_choice', '["A natural monument over course and distance","Distance over an artificial monument","Quantity over course","Course over a natural monument"]'::jsonb, 'A natural monument over course and distance', 'The hierarchy is natural monument > artificial monument > adjoinder > course > distance > quantity. A natural monument outranks course and distance; the other options invert the order.', 'medium', 'acc00003-0000-0000-0000-000000000003', 'acc03b11-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000017', 'When parcels are conveyed sequentially and their descriptions overlap, the conflict is resolved by:', 'multiple_choice', '["Senior/junior rights, with the junior absorbing excess or deficiency","Proportionate apportionment between the two parcels","Splitting the overlap equally","Awarding the overlap to the larger parcel"]'::jsonb, 'Senior/junior rights, with the junior absorbing excess or deficiency', 'Sequential conveyances follow senior/junior rights: the senior takes its full description and the junior takes the remainder. Proportionate apportionment applies to simultaneously created (platted) lots, not sequential carve-outs.', 'medium', 'acc00003-0000-0000-0000-000000000003', 'acc03b12-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000018', 'A circular curve has R = 500.00 ft and central angle delta = 30 deg. Its arc (curve) length L (ft) is closest to:', 'numeric_input', '[]'::jsonb, '261.80', 'L = R * delta * PI / 180 = 500 * 30 * 3.14159265 / 180 = 500 * 0.523599 = 261.80 ft.', 'medium', 'acc00003-0000-0000-0000-000000000003', 'acc03b13-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000019', 'For a simple horizontal curve, the tangent distance T equals:', 'multiple_choice', '["R * tan(delta/2)","R * sin(delta/2)","2 * R * sin(delta/2)","R * delta * PI / 180"]'::jsonb, 'R * tan(delta/2)', 'T = R*tan(delta/2). The long chord is 2R*sin(delta/2) and the arc length is R*delta*PI/180.', 'medium', 'acc00003-0000-0000-0000-000000000003', 'acc03b13-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000020', 'Survey software that accepts redundant observations and weights them by their precision, reporting error ellipses, performs:', 'multiple_choice', '["A least-squares adjustment","A compass (Bowditch) adjustment","A transit-rule adjustment","No adjustment at all"]'::jsonb, 'A least-squares adjustment', 'Least squares rigorously weights every observation by its precision and yields error ellipses and statistics. The compass and transit rules use fixed length/component weighting and a single loop.', 'medium', 'acc00003-0000-0000-0000-000000000003', 'acc03b14-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3130-0000-0000-0000-000000000021', 'Texas land descends from original General Land Office surveys described by metes and bounds, and Texas has no federal PLSS township-range grid.', 'true_false', '["True","False"]'::jsonb, 'True', 'Texas retained its public lands at annexation, so original title flows from the State via the GLO, described by metes-and-bounds keyed to survey name + abstract number. There is no federal PLSS grid in Texas.', 'easy', 'acc00003-0000-0000-0000-000000000003', 'acc03b15-0000-0000-0000-000000000001', ARRAY['buildout','module-31']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
