INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3160-0000-0000-0000-000000000001', 'A traverse course runs N {{ang:f0}} deg E for a horizontal distance of {{dist:f2}} ft. Compute the DEPARTURE (east-west component) of this course in feet.', 'numeric_input', '[]'::jsonb, '0', 'Departure = d sin(alpha) = {{dist:f2}} x sin({{ang:f0}} deg) = {{_answer}} ft east. (Its latitude, d cos(alpha), would be {{lat:f2}} ft north.)', 'medium', 'acc00003-0000-0000-0000-000000000003', NULL, ARRAY['buildout','module-31','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3150-0000-0000-0000-000000000001', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3160-0000-0000-0000-000000000002', 'After summing all courses of a closed-loop traverse, the latitudes total {{sumLat:f3}} ft and the departures total {{sumDep:f3}} ft. Compute the LINEAR MISCLOSURE (ft).', 'numeric_input', '[]'::jsonb, '0', 'The linear misclosure is the hypotenuse of the latitude and departure misclosures: E = hypot({{sumLat:f3}}, {{sumDep:f3}}) = {{_answer}} ft.', 'medium', 'acc00003-0000-0000-0000-000000000003', NULL, ARRAY['buildout','module-31','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3150-0000-0000-0000-000000000002', 0.002);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3160-0000-0000-0000-000000000003', 'A closed traverse has a latitude misclosure of {{misLat:f3}} ft over a perimeter of {{perim:f2}} ft. Using the compass (Bowditch) rule, compute the LATITUDE CORRECTION (ft) applied to a course that is {{dist:f2}} ft long.', 'numeric_input', '[]'::jsonb, '0', 'The compass rule distributes the latitude misclosure in proportion to course length: C_Lat = -E_L x (d/P) = -({{misLat:f3}}) x ({{dist:f2}}/{{perim:f2}}) = {{_answer}} ft. The negative sign removes the misclosure.', 'medium', 'acc00003-0000-0000-0000-000000000003', NULL, ARRAY['buildout','module-31','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3150-0000-0000-0000-000000000003', 0.0005);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3160-0000-0000-0000-000000000004', 'A balanced triangular parcel has corners A(E={{xa:f2}}, N={{ya:f2}}), B(E={{xb:f2}}, N={{yb:f2}}), and C(E={{xc:f2}}, N={{yc:f2}}). Using the coordinate (shoelace) method, compute the AREA in square feet.', 'numeric_input', '[]'::jsonb, '0', 'The coordinate (shoelace) area of the triangle is A = (1/2)|xa(yb-yc) + xb(yc-ya) + xc(ya-yb)| = {{_answer}} sq ft, using the balanced coordinates in order.', 'medium', 'acc00003-0000-0000-0000-000000000003', NULL, ARRAY['buildout','module-31','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3150-0000-0000-0000-000000000004', 0.5);
