INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3160-0000-0000-0000-000000000005', 'A simple horizontal circular curve has radius R = {{R:f2}} ft and central angle delta = {{delta:f1}} deg. Compute the ARC (curve) LENGTH L in feet.', 'numeric_input', '[]'::jsonb, '0', 'Arc length uses delta in radians: L = R*toRad(delta) = {{R:f2}} x ({{delta:f1}} x PI/180) = {{_answer}} ft. (Tangent T = R tan(delta/2) = {{T:f2}} ft; long chord C = 2R sin(delta/2) = {{C:f2}} ft.)', 'medium', 'acc00003-0000-0000-0000-000000000003', NULL, ARRAY['buildout','module-31','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3150-0000-0000-0000-000000000005', 0.1);
