INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3160-0000-0000-0000-000000000006', 'A course has the bearing S {{B:f1}} deg E. Express its direction as an AZIMUTH (degrees, clockwise from north).', 'numeric_input', '[]'::jsonb, '0', 'In the SE quadrant (S B E) the azimuth is 180 - B = 180 - {{B:f1}} = {{_answer}} deg, measured clockwise from north.', 'easy', 'acc00003-0000-0000-0000-000000000003', NULL, ARRAY['buildout','module-31','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3150-0000-0000-0000-000000000006', 0.05);
