-- 362_buildout_m31.sql (GENERATED) — fill empty lessons for "ACC SRVY 1341 — Land Surveying"
-- Module acc00003-0000-0000-0000-000000000003. Namespaced by tag 'buildout' / created_by 'buildout:m31' so pre-existing rows are untouched.
BEGIN;
DELETE FROM question_bank     WHERE module_id='acc00003-0000-0000-0000-000000000003' AND 'buildout' = ANY(tags);
DELETE FROM flashcards        WHERE module_id='acc00003-0000-0000-0000-000000000003' AND 'buildout' = ANY(tags);
DELETE FROM problem_templates WHERE module_id='acc00003-0000-0000-0000-000000000003' AND created_by='buildout:m31';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=20, key_takeaways=ARRAY['SRVY 1341 is a core land-surveying course built around the closed traverse: measure, check, adjust, and compute coordinates and area.','Topics progress from distance and angle measurement, through traverse adjustment and coordinate geometry, to boundary determination and subdivision.','Texas surveying is regulated by the Texas Board of Professional Engineers and Land Surveyors (TBPELS) and rooted in the General Land Office (GLO) original-survey system — no PLSS grid.','Accuracy, redundant observations, and a defensible record are the habits this course builds.']::text[], learning_objectives=ARRAY['Describe the scope of SRVY 1341 and how traversing ties field measurement to computed boundaries.','Identify the major topics of the course: measurement, angles, traverse adjustment, COGO, area, and boundary principles.','Recognize the Texas regulatory context (TBPELS, GLO) that frames professional land surveying.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc03b00-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc03b00-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Measured taped distances must be corrected for tape standard length, temperature, tension, sag, and slope before use.','Temperature correction = alpha * (T - T0) * L, with alpha = 0.00000645 per deg F for steel.','Slope-to-horizontal: H = sqrt(L^2 - h^2) (exact) or approximately H = L - h^2/(2L) for small slopes.','A correction that makes the tape effectively longer adds to the distance when laying out and subtracts when measuring — keep the sign rule straight.']::text[], learning_objectives=ARRAY['Describe taping (chaining) procedure and the sources of error in measured distances.','Apply tape corrections for standardization (length), temperature, tension (pull), sag, and slope.','Compute a corrected horizontal distance from a measured (recorded) distance.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc03b01-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc03b01-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['A compass reads a magnetic bearing as a quadrant direction (N/S, angle, E/W); azimuths run clockwise 0-360 from north.','DMS to DD: DD = deg + min/60 + sec/3600; reverse by extracting whole degrees, then minutes, then seconds.','Bearings are limited to 0-90 within a quadrant; azimuths span the full circle.','Compass surveying is low precision (magnetic, +/- ~15 minutes) and is superseded by total stations for boundary work.']::text[], learning_objectives=ARRAY['Read and record bearings with a compass and distinguish bearings from azimuths.','Convert angles between decimal degrees (DD) and degrees-minutes-seconds (DMS).','Apply chaining corrections in combination with compass directions to lay out a short traverse.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc03b02-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc03b02-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Declination is the angle between magnetic north and true (geodetic) north; east declination is added, west is subtracted, when going from magnetic to true.','Declination changes with location and time (secular variation), so the date of an old survey matters for retracement.','Smartphone compass apps are reconnaissance aids only, not survey-grade instruments.','Complete, legible, contemporaneous field notes are a legal record; never erase, and reference the original surveyor''s footsteps.']::text[], learning_objectives=ARRAY['Define magnetic declination and convert between magnetic and true (geodetic) bearings.','Evaluate the accuracy and proper use of smartphone compass apps in survey reconnaissance.','Apply professional field-notekeeping standards and identify reputable surveying trade publications.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc03b03-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc03b03-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['Instruments are precision optics and electronics: lift by the standards, keep dry, transport in the case, and never leave on a tripod unattended.','A stable tripod with firmly seated, equal-tension legs and a clean tribrach is the foundation of every measurement.','Routine field checks (plate level, optical/laser plummet, collimation) catch drift before it corrupts data.','Follow a documented maintenance and periodic professional-calibration schedule; keep calibration records.']::text[], learning_objectives=ARRAY['Apply correct handling, transport, and storage practices for total stations and levels.','Set up a stable tripod and recognize how tripod faults propagate into measurement error.','Describe a maintenance and calibration schedule that keeps instruments within tolerance.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc03b04-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc03b04-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Setup is an iterative loop: rough-center with the plummet, coarse-level by adjusting tripod legs, fine-level with the leveling screws, then re-center by sliding the tribrach.','Fine leveling: align the plate bubble parallel to two screws and center it, rotate 90 degrees, center with the third screw, then check all around.','Centering (setup) error is most damaging on short sights and produces angular error.','Record the height of instrument (HI) carefully; it feeds trigonometric leveling and 3D reductions.']::text[], learning_objectives=ARRAY['Set up and level a total station precisely over a ground mark using the plummet and leveling screws.','Distinguish coarse leveling (tripod legs/bubble) from fine leveling (leveling screws) and centering.','Explain how setup (centering) error and the height of instrument affect measured angles and reductions.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc03b05-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc03b05-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Interior angles sum to (n-2)*180 for a closed polygon; deflection angles sum to 360; exterior angles sum to (n+2)*180.','Angle to the right (clockwise from backsight to foresight) is the modern total-station convention.','Forward azimuth of next course = back azimuth of current course + angle to the right (mod 360).','Observing face-left and face-right (D&R) and repeating angles cancels collimation and axis errors.']::text[], learning_objectives=ARRAY['Distinguish interior, exterior, deflection, and angle-to-the-right measurements.','Compute azimuths and bearings of successive courses from measured angles.','Apply face-left/face-right observation and angle repetition to control instrumental error.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc03b06-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc03b06-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=45, key_takeaways=ARRAY['Lat = d*cos(bearing), Dep = d*sin(bearing); for a closed loop the sums should be zero, and the residuals are the misclosures.','Compass (Bowditch) rule: correction proportional to course length; transit rule: proportional to component magnitude (|Lat|, |Dep|).','Transit rule assumes angles are more precise than distances and disturbs bearings less than the compass rule.','Least squares rigorously weights every observation by its precision and is the modern professional standard.']::text[], learning_objectives=ARRAY['Compute latitudes and departures and the misclosure of a closed traverse.','Apply the compass (Bowditch) and transit rules to distribute misclosure, and contrast their assumptions.','Recognize least-squares adjustment as the rigorous modern alternative.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc03b07-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc03b07-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['The midterm covers Weeks 1-7: taping corrections, bearings/azimuths and DMS, declination, instrument care/setup, angle types, latitudes/departures, misclosure, and the compass and transit rules.','Be fluent in the full short-traverse workflow: components -> misclosure -> ratio -> adjust.','Show every step with units and a check; partial credit follows disciplined work.','Review by re-working problems, not just re-reading notes.']::text[], learning_objectives=ARRAY['Integrate distance, direction, angle, and adjustment skills from Weeks 1-7.','Execute a complete short-traverse computation: lat/dep, misclosure, ratio of closure, and adjustment.','Self-assess readiness using a structured review of the first-half learning objectives.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc03b08-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc03b08-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=45, key_takeaways=ARRAY['Inverse: distance = hypot(dE, dN); azimuth = atan2(dE, dN) reduced to 0-360.','atan2(dE, dN) (note the order) returns the azimuth measured clockwise from north.','Bearing-bearing intersection finds where two lines of known direction from two known points cross.','COGO turns measured/computed coordinates into distances, directions, and intersection points for layout and checks.']::text[], learning_objectives=ARRAY['Compute the distance and azimuth between two coordinated points (the inverse).','Solve bearing-bearing and bearing-distance intersection problems.','Apply coordinate geometry (COGO) to locate points and check field work.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc03b09-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc03b09-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=45, key_takeaways=ARRAY['Coordinate (shoelace) area: A = (1/2)|sum(x_i*y_{i+1} - x_{i+1}*y_i)| on a balanced traverse.','DMD method: area = (1/2)|sum(DMD_i * Lat_i)|, where DMD accumulates departures; equivalent to the coordinate method.','Always balance (adjust) the traverse first; an unclosed figure gives a wrong area.','1 acre = 43,560 sq ft; in Texas records 1 acre ~ 5,645.4 sq varas and 1 labor ~ 177.1 acres.']::text[], learning_objectives=ARRAY['Compute a parcel area from balanced coordinates by the coordinate (shoelace) method.','Compute area by the double-meridian-distance (DMD) method and show its equivalence.','Convert areas between square feet, acres, and Texas units, and apply the balance-first rule.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc03b10-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc03b10-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Boundary location is an evidence problem: monuments, records, and measurements are weighed, not just recomputed.','Dignity of calls (Texas): natural monuments > artificial monuments > adjoinder > course > distance > quantity/area.','A found, identified original monument controls over conflicting course-and-distance calls.','All calls yield to the intent of the parties and the footsteps of the original surveyor (Stafford v. King).']::text[], learning_objectives=ARRAY['Distinguish natural and artificial monuments and rank evidence by dignity of calls.','Explain the controlling role of found original monuments over recomputed measurements.','Apply the Texas dignity-of-calls hierarchy and intent in evaluating boundary evidence.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc03b11-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc03b11-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['A resurvey re-establishes the ORIGINAL lines and corners; the original surveyor''s footsteps control over inconsistent field-note calls.','Sequential conveyances follow senior/junior rights: the senior takes its full description, the junior absorbs excess or deficiency.','Simultaneous (platted) lots are of equal dignity: excess/deficiency is apportioned proportionately, never absorbed by one lot.','Proportionate measurement is a last resort, used only for genuinely lost corners after monuments and collateral evidence fail.']::text[], learning_objectives=ARRAY['Apply the footsteps doctrine: a resurvey retraces, it does not relocate, the original boundary.','Apply senior/junior rights and proportionate measurement to sequential and simultaneous conveyances.','Recognize the role of occupation, acquiescence, and the surveyor''s duty in retracement.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc03b12-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc03b12-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=45, key_takeaways=ARRAY['A subdivision plat creates lots simultaneously, with blocks, lot lines, streets/rights-of-way, and easements dedicated as shown.','Curve tangent: T = R*tan(delta/2); curve length: L = R*toRad(delta) = R*delta*PI/180.','Long chord: C = 2*R*sin(delta/2); the degree of curve relates R to a standard arc or chord.','Subdivision lines on curved frontage are described by curve data (radius, delta, arc length, chord bearing/length).']::text[], learning_objectives=ARRAY['Describe subdivision platting concepts: blocks, lots, rights-of-way, and easements.','Compute the principal elements of a simple horizontal circular curve from radius and central angle.','Relate curve data (R, delta, T, L, C) used on plats and in roadway alignments.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc03b13-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc03b13-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Survey software automates lat/dep, misclosure, ratio of closure, adjustment, coordinates, and area, but requires correct input and units.','Least-squares software weights observations by precision and reports error ellipses and statistics.','Always verify software output with independent checks (inverse, closure, sanity of magnitudes).','Document the software, settings, datum, and grid/ground basis used.']::text[], learning_objectives=ARRAY['Use COGO and survey software to compute, adjust, and report a traverse.','Contrast spreadsheet/compass-rule workflows with rigorous least-squares software.','Apply verification habits so software output is checked, not blindly trusted.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc03b14-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc03b14-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Texas surveying is regulated by TBPELS under Tex. Occ. Code ch. 1071, with standards of practice in 22 TAC ch. 138.','The course arc: measure (distance/angle) -> check and adjust (misclosure, compass/transit) -> compute (coordinates, area) -> determine the boundary (evidence, dignity of calls, footsteps).','Boundary location is governed by intent, monuments, and the original surveyor''s footsteps, not by recomputed measurement alone.','Professional duties include accuracy standards, proper records, basis of bearings, and continuing competence.']::text[], learning_objectives=ARRAY['Summarize the Texas professional standards governing land surveying practice.','Synthesize the course: measurement, adjustment, COGO, area, and boundary determination.','Prepare for the final exam by reviewing the full traverse-to-boundary workflow.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc03b15-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc03b15-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['The final is comprehensive: measurement, adjustment, COGO, area, curves, subdivision, and boundary determination.','Run a complete closed traverse: lat/dep -> misclosure -> ratio -> adjust -> coordinates -> area.','Solve inverse, intersection, and curve (T, L, C) problems accurately with correct units.','Answer boundary-evidence questions by intent, dignity of calls, and the footsteps doctrine.']::text[], learning_objectives=ARRAY['Demonstrate the complete traverse-to-boundary workflow under exam conditions.','Apply coordinate geometry, area computation, and curve calculations to applied problems.','Reason correctly about boundary evidence using Texas dignity of calls and footsteps.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc03b16-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc03b16-0000-0000-0000-000000000001';
  'eeee3150-0000-0000-0000-000000000001', 'Latitude and departure of a course', 'Latitude and departure of a course', 'Land Surveying — Traverse', 'Latitude and departure', 'numeric_input', 'medium', 'A traverse course runs N {{ang:f0}} deg E for a horizontal distance of {{dist:f2}} ft. Compute the DEPARTURE (east-west component) of this course in feet.', 'dist*sin(toRad(ang))', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"ang","type":"integer","min":15,"max":75},{"name":"dist","type":"float","min":150,"max":700,"decimals":2}]'::jsonb, '[{"name":"lat","formula":"dist*cos(toRad(ang))"}]'::jsonb, '[{"step_number":1,"title":"Departure formula","formula":"Dep = d sin(alpha)","calculation_template":"{{dist:f2}} x sin({{ang:f0}} deg)"},{"step_number":2,"title":"Compute","result_template":"Departure = {{_answer}} ft (east, positive)"}]'::jsonb, '{"method":"none"}'::jsonb, 'Departure = d sin(alpha) = {{dist:f2}} x sin({{ang:f0}} deg) = {{_answer}} ft east. (Its latitude, d cos(alpha), would be {{lat:f2}} ft north.)', 'acc00003-0000-0000-0000-000000000003', ARRAY['buildout','module-31','practice']::text[], true, 'buildout:m31');
  'eeee3150-0000-0000-0000-000000000002', 'Linear misclosure of a closed traverse', 'Linear misclosure of a closed traverse', 'Land Surveying — Traverse', 'Misclosure', 'numeric_input', 'medium', 'After summing all courses of a closed-loop traverse, the latitudes total {{sumLat:f3}} ft and the departures total {{sumDep:f3}} ft. Compute the LINEAR MISCLOSURE (ft).', 'hypot(sumLat, sumDep)', '{"decimals":3,"unit":"ft","tolerance":0.002}', '[{"name":"sumLat","type":"float","min":-0.2,"max":0.2,"decimals":3},{"name":"sumDep","type":"float","min":-0.2,"max":0.2,"decimals":3}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Misclosure formula","formula":"E = sqrt(sumLat^2 + sumDep^2)","calculation_template":"sqrt(({{sumLat:f3}})^2 + ({{sumDep:f3}})^2)"},{"step_number":2,"title":"Compute","result_template":"Linear misclosure = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The linear misclosure is the hypotenuse of the latitude and departure misclosures: E = hypot({{sumLat:f3}}, {{sumDep:f3}}) = {{_answer}} ft.', 'acc00003-0000-0000-0000-000000000003', ARRAY['buildout','module-31','practice']::text[], true, 'buildout:m31');
  'eeee3150-0000-0000-0000-000000000003', 'Compass (Bowditch) rule latitude correction for one course', 'Compass (Bowditch) rule latitude correction for one course', 'Land Surveying — Traverse', 'Compass rule adjustment', 'numeric_input', 'medium', 'A closed traverse has a latitude misclosure of {{misLat:f3}} ft over a perimeter of {{perim:f2}} ft. Using the compass (Bowditch) rule, compute the LATITUDE CORRECTION (ft) applied to a course that is {{dist:f2}} ft long.', '-misLat*(dist/perim)', '{"decimals":4,"unit":"ft","tolerance":0.0005}', '[{"name":"misLat","type":"float","min":-0.18,"max":0.18,"decimals":3},{"name":"perim","type":"float","min":1000,"max":3200,"decimals":2},{"name":"dist","type":"float","min":150,"max":550,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Compass rule correction","formula":"C_Lat = -E_L x (d / P)","calculation_template":"-({{misLat:f3}}) x ({{dist:f2}} / {{perim:f2}})"},{"step_number":2,"title":"Compute","result_template":"Latitude correction = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The compass rule distributes the latitude misclosure in proportion to course length: C_Lat = -E_L x (d/P) = -({{misLat:f3}}) x ({{dist:f2}}/{{perim:f2}}) = {{_answer}} ft. The negative sign removes the misclosure.', 'acc00003-0000-0000-0000-000000000003', ARRAY['buildout','module-31','practice']::text[], true, 'buildout:m31');
  'eeee3150-0000-0000-0000-000000000004', 'Area of a triangular parcel by coordinates', 'Area of a triangular parcel by coordinates', 'Land Surveying — Area', 'Coordinate (shoelace) area', 'numeric_input', 'medium', 'A balanced triangular parcel has corners A(E={{xa:f2}}, N={{ya:f2}}), B(E={{xb:f2}}, N={{yb:f2}}), and C(E={{xc:f2}}, N={{yc:f2}}). Using the coordinate (shoelace) method, compute the AREA in square feet.', 'abs((xa*(yb-yc)+xb*(yc-ya)+xc*(ya-yb))/2)', '{"decimals":2,"unit":"sq ft","tolerance":0.5}', '[{"name":"xa","type":"float","min":1000,"max":1100,"decimals":2},{"name":"ya","type":"float","min":1000,"max":1100,"decimals":2},{"name":"bx","type":"float","min":300,"max":600,"decimals":2},{"name":"by","type":"float","min":-50,"max":50,"decimals":2},{"name":"cx","type":"float","min":-50,"max":50,"decimals":2},{"name":"cy","type":"float","min":300,"max":600,"decimals":2}]'::jsonb, '[{"name":"xb","formula":"xa+bx"},{"name":"yb","formula":"ya+by"},{"name":"xc","formula":"xa+cx"},{"name":"yc","formula":"ya+cy"}]'::jsonb, '[{"step_number":1,"title":"Shoelace formula","formula":"A = (1/2)|xa(yb-yc) + xb(yc-ya) + xc(ya-yb)|","calculation_template":"(1/2)|{{xa:f2}}({{yb:f2}}-{{yc:f2}}) + {{xb:f2}}({{yc:f2}}-{{ya:f2}}) + {{xc:f2}}({{ya:f2}}-{{yb:f2}})|"},{"step_number":2,"title":"Compute","result_template":"Area = {{_answer}} sq ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The coordinate (shoelace) area of the triangle is A = (1/2)|xa(yb-yc) + xb(yc-ya) + xc(ya-yb)| = {{_answer}} sq ft, using the balanced coordinates in order.', 'acc00003-0000-0000-0000-000000000003', ARRAY['buildout','module-31','practice']::text[], true, 'buildout:m31');
  'eeee3150-0000-0000-0000-000000000005', 'Horizontal curve tangent and length from R and delta', 'Horizontal curve tangent and length from R and delta', 'Land Surveying — Curves', 'Curve elements', 'numeric_input', 'medium', 'A simple horizontal circular curve has radius R = {{R:f2}} ft and central angle delta = {{delta:f1}} deg. Compute the ARC (curve) LENGTH L in feet.', 'R*toRad(delta)', '{"decimals":2,"unit":"ft","tolerance":0.1}', '[{"name":"R","type":"float","min":300,"max":1200,"decimals":2},{"name":"delta","type":"float","min":10,"max":80,"decimals":1}]'::jsonb, '[{"name":"T","formula":"R*tan(toRad(delta/2))"},{"name":"C","formula":"2*R*sin(toRad(delta/2))"}]'::jsonb, '[{"step_number":1,"title":"Arc length formula","formula":"L = R * delta(radians) = R * delta * PI/180","calculation_template":"{{R:f2}} x {{delta:f1}} x PI/180"},{"step_number":2,"title":"Compute","result_template":"Arc length L = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Arc length uses delta in radians: L = R*toRad(delta) = {{R:f2}} x ({{delta:f1}} x PI/180) = {{_answer}} ft. (Tangent T = R tan(delta/2) = {{T:f2}} ft; long chord C = 2R sin(delta/2) = {{C:f2}} ft.)', 'acc00003-0000-0000-0000-000000000003', ARRAY['buildout','module-31','practice']::text[], true, 'buildout:m31');
  'eeee3150-0000-0000-0000-000000000006', 'Convert a bearing to an azimuth', 'Convert a bearing to an azimuth', 'Land Surveying — Directions', 'Bearing and azimuth', 'numeric_input', 'easy', 'A course has the bearing S {{B:f1}} deg E. Express its direction as an AZIMUTH (degrees, clockwise from north).', '180 - B', '{"decimals":1,"unit":"deg","tolerance":0.05}', '[{"name":"B","type":"float","min":10,"max":80,"decimals":1}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"SE-quadrant rule","formula":"Az = 180 - B","calculation_template":"180 - {{B:f1}}"},{"step_number":2,"title":"Compute","result_template":"Azimuth = {{_answer}} deg"}]'::jsonb, '{"method":"none"}'::jsonb, 'In the SE quadrant (S B E) the azimuth is 180 - B = 180 - {{B:f1}} = {{_answer}} deg, measured clockwise from north.', 'acc00003-0000-0000-0000-000000000003', ARRAY['buildout','module-31','practice']::text[], true, 'buildout:m31');
COMMIT;
SELECT 'm31 ACC SRVY 1341 — Land Surveying: ' || (SELECT count(*) FROM lesson_blocks lb JOIN learning_lessons l ON l.id=lb.lesson_id WHERE l.module_id='acc00003-0000-0000-0000-000000000003') || ' blocks.' AS status;